              "content": "/**\n * Advisory Model Escalation — Policy Config\n * ============================================\n * Escalation ladder, heuristic thresholds, keyword lists.\n * Mutable at runtime — UI can toggle enable/disable.\n */\n\nexport interface AdvisorPolicy {\n  /** Global kill switch */\n  enabled: boolean;\n\n  /**\n   * Escalation ladder — ordered low → high capability.\n   * Each entry matches model name patterns (case-insensitive substring).\n   * A model can only escalate to entries ABOVE it in the ladder.\n   */\n  ladder: Array<{\n    /** Human label shown in the suggestion */\n    label: string;\n    /** Patterns to match against model name/id (any match = this tier) */\n    patterns: string[];\n    /** The model string to pass to the provider when escalating */\n    modelId: string;\n    /** Provider hint */\n    provider: string;\n  }>;\n\n  /** Uncertainty signal phrases in model responses */\n  uncertaintyPhrases: string[];\n\n  /** Keywords in user messages that indicate complex requests */\n  complexityKeywords: string[];\n\n  /** Token estimate threshold — user messages above this are \"complex\" */\n  complexTokenThreshold: number;\n\n  /** Minimum response tokens expected for a complex request */\n  shortResponseThreshold: number;\n\n  /** How many consecutive uncertain/short responses before suggesting */\n  consecutiveThreshold: number;\n}\n\nexport const advisorPolicy: AdvisorPolicy = {\n  enabled: true,\n\n  ladder: [\n    {\n      label: \"MiMo Flash\",\n      patterns: [\"mimo-flash\", \"mimo-v2-flash\", \"moonshotai/mimo-flash\", \"xiaomi/mimo-v2-flash\"],\n      modelId: \"xiaomi/mimo-v2-flash-20251210\",\n      provider: \"openrouter\",\n    },\n    {\n      label: \"MiMo Pro\",\n      patterns: [\"mimo-pro\", \"mimo-v2-pro\", \"mimo pro\", \"moonshotai/mimo-pro\", \"xiaomi/mimo-v2-pro\"],\n      modelId: \"xiaomi/mimo-v2-pro-20251210\",\n      provider: \"openrouter\",\n    },\n    {\n      label: \"Claude Sonnet 4.6\",\n      patterns: [\"claude-sonnet\", \"sonnet-4\", \"sonnet 4\", \"claude-4\"],\n      modelId: \"anthropic/claude-sonnet-4-6\",\n      provider: \"openrouter\",\n    },\n    {\n      label: \"Claude Opus 4.6\",\n      patterns: [\"claude-opus\", \"opus-4\", \"opus 4\"],\n      modelId: \"anthropic/claude-opus-4-6\",\n      provider: \"openrouter\",\n    },\n  ],\n\n  uncertaintyPhrases: [\n    \"i'm not sure\",\n    \"i don't know\",\n    \"i can't\",\n    \"i cannot\",\n    \"beyond my\",\n    \"unable to\",\n    \"i'm unable\",\n    \"i don't have the ability\",\n    \"outside my capabilities\",\n    \"not equipped to\",\n    \"i lack the\",\n    \"this is beyond\",\n    \"i may not be the best\",\n    \"you might want to use a more\",\n    \"a more capable model\",\n    \"i'm limited\",\n    \"my training\",\n    \"as a language model\",\n  ],\n\n  complexityKeywords: [\n    \"analyze\",\n    \"compare\",\n    \"reason through\",\n    \"architecture\",\n    \"security\",\n    \"audit\",\n    \"deep dive\",\n    \"explain in detail\",\n    \"trace through\",\n    \"step by step\",\n    \"pros and cons\",\n    \"trade-offs\",\n    \"tradeoffs\",\n    \"root cause\",\n    \"debug\",\n    \"refactor\",\n    \"design pattern\",\n    \"evaluate\",\n    \"comprehensive\",\n    \"thorough\",\n  ],\n\n  complexTokenThreshold: 800,\n  shortResponseThreshold: 150,\n  consecutiveThreshold: 2,\n};\n",
