              "path": "apps/api/src/config/prompt-versions.ts",
              "content": "/**\n * Prompt Version Pinning\n * =======================\n * Tracks which version of each critical system prompt is active.\n * Bump manually when prompts change. Never auto-incremented.\n * Every receipt includes the prompt version that handled it.\n */\n\nexport const PROMPT_VERSIONS: Record<string, string> = {\n  grimoire:   \"2.1.0\",\n  codex:      \"1.0.0\",\n  velum:      \"1.0.0\",\n  archelon:   \"2.0.0\",\n  colloquium: \"1.3.0\",\n  symposium:  \"1.0.0\",\n  \"simple-mode\": \"1.0.0\",\n  crucible:   \"1.1.0\",\n};\n",
