              "path": "apps/api/src/config/public-mode.ts",
              "content": "/**\n * Public Mode Configuration\n * ==================================\n * When SQUIDLEY_PUBLIC_MODE=true, restricts the UI to customer-facing modules only.\n * Used for Simple Mode / service business deployments and demos.\n */\n\nexport const PUBLIC_MODE_CONFIG = {\n  enabled: process.env[\"SQUIDLEY_PUBLIC_MODE\"] === \"true\",\n\n  // Modules visible in public mode\n  visible_modules: [\"colloquium\", \"simple\", \"eidolon\"],\n\n  // Modules hidden in public mode\n  hidden_modules: [\n    \"grimoire\", \"crucible\", \"forax\", \"archelon\",\n    \"tabularium\", \"velum\", \"nous\", \"augury\", \"oculus\",\n    \"legatus\", \"cursus\", \"imperium\", \"fabrica\",\n    \"symposium\", \"archivum\", \"memoria\", \"animus\",\n    \"forax\", \"brain-map\",\n  ],\n\n  // Features disabled in public mode\n  disabled_features: {\n    model_selection: true,\n    personality_selection: true,\n    thinking_toggle: true,\n    receipt_display: true,\n    cost_display: true,\n    provider_display: true,\n  },\n\n  // What shows instead of Squidley branding\n  public_branding: {\n    show_powered_by: false,\n    show_model_name: false,\n    assistant_name: \"Assistant\", // overridable per deployment via env\n  },\n} as const;\n\nexport type PublicModeConfig = typeof PUBLIC_MODE_CONFIG;\n",
