urce: \"chat-exchange\" });\n            } else {\n              memory.addToWorking({ role: \"user\", content: lastUser.content, timestamp: Date.now() });\n              memory.addToWorking({ role: \"assistant\", content: fullResponseText, timestamp: Date.now() });\n            }\n          }\n        }\n\n        // Extract side-effect proposals — NEVER execute from model output\n        if (approvals && (legatusCreationIntent || archivumSaveIntent) && fullResponseText) {\n          const streamProposals = await extractSideEffectProposals(fullResponseText, req.log, approvals);\n          if (streamProposals.length > 0) {\n            reply.raw.write(`data: ${JSON.stringify({ type: \"proposals\", proposals: streamProposals.map(p => ({ id: p.id, type: p.type, payload: p.payload })) })}\\n\\n`);\n          }\n          await maybeArchivumAutoSave({\n            archivumSaveIntent,\n            proposalsIncludeArchivumSave: streamProposals.some(p => p.type === \"archivum-save\"),\n            userText: [...body.messages].reverse().find(m => m.role === \"user\")?.content ?? null,\n            responseText: fullResponseText,\n            stream: true,\n            logger: req.log,\n          });\n        }\n\n        // Advisory escalation check — after stream completes (skip for Colloquium)\n        const streamLastUser = [...body.messages].reverse().find(m => m.role === \"user\");\n        const streamIsColloquium = body.source === \"colloquium\" || (body.source ?? \"\").includes(\"colloquium\") || (body as unknown as Record<string, unknown>).module === \"colloquium\";\n        if (!streamIsColloquium && streamLastUser && fullResponseText) {\n          const streamSessionId = body.source ?? `session-${Date.now()}`;\n          const streamModelName = (doneChunk.result as { model?: string })?.model ?? options.model ?? \"\";\n          const streamAdvisor = advisorEvaluate(streamLastUser.content, fullResponseText, streamModelName, streamSessionId);\n          if (streamAdvisor) {\n            reply.raw.write(`data: ${JSON.stringify({ type: \"advisor\", ...streamAdvisor })}\\n\\n`);\n            req.log.debug({ event: \"advisor:suggestion\", model: streamModelName, target: streamAdvisor.suggestedModel, confidence: streamAdvisor.confidence });\n          }\n        }\n      }\n    } catch (err) {\n      const runs = getRuns();\n      if (runs && colloquiumRunId) runs.failRun(colloquiumRunId, String(err).slice(0, 300));\n      reply.raw.write(`data: ${JSON.stringify({ type: \"error\", error: String(err) })}\\n\\n`);\n    } finally {\n      // Contract: a tool-using turn may NEVER close the stream without a\n      // user-visible final assistant message. If we got here without one,\n      // emit a deterministic in-character fallback so the user is never\n      // stranded watching tool/evidence UI with no answer.\n      if (!synthesisDebug.finalUserVisibleMessageSent) {\n        synthesisDebug.streamClosedBeforeFinal = true;\n        const lastUserContent = lastPlainUser?.content ?? null;\n        const fallbackText = synthesisDebug.toolFailed\n          ? buildToolFailureFallback(lastUserContent, toolEvidence, synthesisDebug.failureReason ?? \"stream closed before final answer\")\n          : buildSynthesisFallback(lastUserContent, toolEvidence, synthesisDebug.failureReason ?? \"stream closed before final answer\");\n        const safeFallback = ensureNonEmptyAssistantText(fallbackText);\n        try {\n          reply.raw.write(`data: ${JSON.stringify({ type: \"content_replace\", text: safeFallback })}\\n\\n`);\n          synthesisDebug.finalUserVisibleMessageSent = true;\n          synthesisDebug.fallbackUsed = true;\n        } catch { /* stream may already be torn down */ }\n        req.log.error({\n          event: \"chat:stream-closed-before-final\",\n          requestClass: synthesisDebug.requestClass,\n          toolActivity: synthesisDebug.toolActivity,\n          toolsUsed: synthesisDebug.toolsUsed,\n          postToolModelCalled: synthesisDebug.postToolModelCalled,\n          postToolTextPresent: synthesisDebug.postToolTextPresent,\n          postToolFinalizationReason: synthesisDebug.postToolFinalizationReason,\n          failureReason: synthesisDebug.failureReason,\n        });\n      }\n      reply.raw.write(\"data: [DONE]\\n\\n\");\n      reply.raw.end();\n    }\n  });\n\n  // ── Turn-local tool-exposure reports ───────────────────────────────────\n  // Operator surface for \"what hands did Squidley actually have on turn X?\"\n  // The report is written at the chat decision seam (see\n  // routes/chat/tool-exposure.ts). Runtime-truth explicitly DOES NOT own\n  // turn-local truth and points consumers here.\n  app.get<{ Params: { id: string } }>(\"/chat/turns/:id/tool-exposure\", async (req, reply) => {\n    const { getTurnExposure } = await import(\"./chat/tool-exposure.js\");\n    const report = getTurnExposure(req.params.id);\n    if (!report) {\n      return reply.status(404).send({\n        error: \"turn_not_found\",\n        detail: \"No recorded tool exposure for this turnId. Either the id is wrong, the turn predates this build, or the in-memory ring evicted it. JSONL evidence lives at state/receipts/turn-exposure-YYYY-MM-DD.jsonl.\",\n      });\n    }\n    return reply.send({ ok: true, report });\n  });\n\n  app.get<{ Querystring: { limit?: string } }>(\"/chat/turns/tool-exposure\", async (req, reply) => {\n    const { listRecentTurnExposure } = await import(\"./chat/tool-exposure.js\");\n    const limit = Math.max(1, Math.min(Number(req.query.limit ?? \"20\") || 20, 200));\n    const reports = listRecentTurnExposure(limit);\n    return reply.send({ ok: true, count: reports.length, reports });\n  });\n\n  // ── Tool approval API (DEPRECATED — use /approvals routes) ──────────────\n  app.get(\"/tools/pending\", async (_req, reply) => {\n    return reply.send({ approvals: [], deprecated: true, redirect: \"/approvals/pending\" });\n  });\n\n  app.post<{ Body: { approvalId: string; status: \"approved\" | \"rejected\" } }>(\"/tools/approve\", async (req, reply) => {\n    return reply.status(410).send({ error: \"Removed. Use POST /approvals/:id/approve or /approvals/:id/reject.\", deprecated: true });\n  });\n\n  app.get(\"/tools/list\", async (_req, reply) => {\n    const tools = getService<{ getTools: () => Array<{ id: string; name: string; description: string; category: string; requiresApproval: boolean; visibility: string }> }>(\"tool-runner\");\n    if (!tools) return reply.status(503).send({ error: \"Tool runner not available\" });\n    return reply.send({ tools: tools.getTools() });\n  });\n\n  app.get(\"/tools/health\", async (_req, reply) => {\n    const tools = getService<{ getHealth: () => { ok: boolean; mode: \"lite\" | \"full\"; loadedTools: number; failedTools: string[]; approvalGateActive: boolean; setupHints: string[] } }>(\"tool-runner\");\n    if (!tools?.getHealth) return reply.status(503).send({ ok: false, error: \"Tool runner not available\" });\n    return reply.send(tools.getHealth());\n  });\n\n  // ── Public modules/capabilities endpoint — safe for model self-description ──\n  app.get(\"/modules/public\", async (_req, reply) => {\n    const modules: Array<{ name: string; description: string; category: string }> = [];\n\n    // Source 1: Module manifests from lifecycle\n    if (platform?.lifecycle?.getModuleManifests) {\n      const manifests = platform.lifecycle.getModuleManifests();\n      for (const m of manifests) {\n        modules.push({\n          name: m.name,\n          description: m.description,\n          category: m.category,\n        });\n      }\n    }\n\n    // Source 2: Public tools summary (grouped by category)\n    const toolRunner = getService<{ getPublicTools: () => Array<{ id: string; name: string; description: string; category: string }> }>(\"tool-runner\");\n    const publicTools = toolRunner?.getPublicTools?.() ?? [];\n    const toolCategories = new Map<string, string[]>();\n    for (const t of publicTools) {\n      const cat = t.category || \"other\";\n      if (!toolCategories.has(cat)) toolCategories.set(cat, []);\n      toolCategories.get(cat)!.push(t.name);\n    }\n\n    return reply.send({\n      modules,\n      toolSummary: Object.fromEntries(toolCategories),\n      publicToolCount: publicTools.length,\n    });\n  });\n\n  // ── Tab self-description — model-safe tab awareness ──────────────────────\n  app.get(\"/tabs/self-description\", async (_req, reply) => {\n    return reply.send(await buildPrimarySquidleyTabsSelfDescription(getService));\n  });\n\n  // ── Side-effect proposals — list and approve ─────────────────────────────\n  app.get(\"/proposals/pending\", async (_req, reply) => {\n    const approvals = getApprovals();\n    if (!approvals) return reply.status(503).send({ error: \"Approval service not available\" });\n    return reply.send({ proposals: listPendingProposalSummaries(approvals) });\n  });\n\n  app.post<{ Body: { proposalId: string; status: \"approved\" | \"rejected\" } }>(\"/proposals/approve\", async (req, reply) => {\n    const approvals = getApprovals();\n    if (!approvals) return reply.status(503).send({ error: \"Approval service not available\" });\n    const { proposalId, status } = req.body;\n    if (status !== \"approved\" && status !== \"rejected\") {\n      return reply.status(400).send({ error: \"status must be 'approved' or 'rejected'\" });\n    }\n    async function writeReceipt(action: string, status: \"success\" | \"failure\", meta: Record<string, unknown>) {\n      return writeRouteReceipt({\n        componentType: \"grimoire:action\",\n        componentName: \"grimoire\",\n        moduleId: \"grimoire\",\n        reason: `grimoire:${action}`,\n        status,\n        surfacedToUser: true,\n        meta: { ...meta, proposalId },\n      });\n    }\n    const legatus = getLegatusRuntime();\n    const result = await decideAndExecuteProposal({\n      approvals,\n      log: req.log,\n      writeReceipt,\n      createAgent: async (cfg) => legatus.createAgent({ ...cfg, createdBy: cfg.createdBy ?? \"squidley\" } as Parameters<typeof legatus.createAgent>[0]),\n      createSkill: async (cfg) => legatus.createSkill({ ...cfg, createdBy: cfg.createdBy ?? \"squidley\" } as Parameters<typeof legatus.createSkill>[0]),\n      saveNote: (input) => saveTextNote(input),\n    }, { proposalId, status });\n    if (!result.ok) return reply.status(result.code).send({ ok: false, error: result.error });\n    return reply.send(result);\n  });\n\n  // ── Advisory escalation dismiss ──────────────────────────────────────────\n  app.post<{ Body: { sessionId: string } }>(\"/advisor/dismiss\", async (req, reply) => {\n    const { sessionId } = req.body;\n    if (!sessionId) return reply.status(400).send({ error: \"sessionId required\" });\n    advisorDismiss(sessionId);\n    return reply.send({ ok: true, sessionId });\n  });\n\n  // ── Memory API ────────────────────────────────────────────────────────────\n  app.post<{ Body: { tier: string; title: string; content: string; project?: string; tags?: string[] } }>(\"/memory\", async (req, reply) => {\n    const memory = getService<{ write: (opts: MemoryWriteOptions) => Promise<string> }>(\"memory\");\n    if (!memory) return reply.status(503).send({ error: \"Memory not available\" });\n    const compositeContent = [req.body.title, req.body.content, ...(req.body.tags ?? [])].filter(Boolean).join(\"\\n\");\n    if (containsWeatherMemoryTerm(compositeContent)) {\n      req.log.info({ event: \"memory:weather-write-skipped\", tier: req.body.tier, source: \"memory-endpoint\" });\n      return reply.status(204).send();\n    }\n    const id = await memory.write(req.body as MemoryWriteOptions);\n    return reply.send({ id });\n  });\n\n  app.get<{ Querystring: { q: string; project?: string; tier?: string } }>(\"/memory/search\", async (req, reply) => {\n    const memory = getService<{ retrieve: (q: string, p?: string) => Promise<{ entries: Array<Record<string,unknown>>; totalTokensEstimate: number; injectionBlock: string }> }>(\"memory\");\n    if (!memory) return reply.status(503).send({ error: \"Memory not available\" });\n    // Pad short queries so FTS doesn't strip them\n    const q = req.query.q ?? \"\";\n    const paddedQ = q.trim().length <= 3 ? `${q} ${q}* zen squidley lab` : q;\n    const result = await memory.retrieve(paddedQ, req.query.project);\n    result.injectionBlock = filterWeatherMemoryBlock(result.injectionBlock);\n    result.entries = result.entries.filter(entry => {\n      const content = [entry[\"title\"], entry[\"content\"], entry[\"summary\"], entry[\"text\"]].filter(Boolean).join(\"\\n\");\n      return !containsWeatherMemoryTerm(content);\n    });\n    // Filter by tier on server side\n    if (req.query.tier && req.query.tier !== \"all\") {\n      result.entries = result.entries.filter(e => e[\"tier\"] === req.query.tier);\n    }\n    return reply.send(result);\n  });\n\n  // List all memories — bypasses FTS, direct SQLite scan\n  app.get<{ Querystring: { tier?: string; limit?: string } }>(\"/memory/list\", async (req, reply) => {\n    const { default: Database } = await import(\"better-sqlite3\");\n    const base = process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n    const dbPath = `${base}/memory/index.db`;\n    const db = new (Database as any)(dbPath, { readonly: true });\n    try {\n      let rows;\n      if (req.query.tier && req.query.tier !== \"all\") {\n        rows = db.prepare(\"SELECT * FROM memory_entries WHERE tier = ? ORDER BY updated_at DESC LIMIT ?\")\n          .all(req.query.tier, parseInt(req.query.limit ?? \"50\"));\n      } else {\n        rows = db.prepare(\"SELECT * FROM memory_entries ORDER BY updated_at DESC LIMIT ?\")\n          .all(parseInt(req.query.limit ?? \"50\"));\n      }\n      const entries = (rows as Array<Record<string,unknown>>).map(row => ({\n        id: row[\"id\"],\n        tier: row[\"tier\"],\n        title: row[\"title\"],\n        content: row[\"content\"],\n        project: row[\"project\"],\n        tags: JSON.parse((row[\"tags\"] as string) ?? \"[]\"),\n        createdAt: row[\"created_at\"],\n        updatedAt: row[\"updated_at\"],\n        score: 1.0,\n      }));\n      return reply.send({ entries, totalTokensEstimate: 0, injectionBlock: \"\" });\n    } catch (err) {\n      req.log.error({ event: \"memory-list-failed\", error: String(err) });\n      return reply.status(500).send({ error: String(err) });\n    } finally {\n      db.close();\n    }\n  });\n\n  app.get(\"/memory/working\", async (_req, reply) => {\n    const memory = getService<{ getWorkingMemory: () => unknown[] }>(\"memory\");\n    if (!memory) return reply.status(503).send({ error: \"Memory not available\" });\n    return reply.send({ messages: memory.getWorkingMemory() });\n  });\n\n  // ── Providers ─────────────────────────────────────────────────────────────\n  app.get(\"/chat/providers\", async (_req, reply) => {\n    const pm = getService<{ getRegisteredProviders: () => string[] }>(\"provider-manager\");\n    if (!pm) return reply.status(503).send({ error: \"Provider manager not available\" });\n    return reply.send({ providers: pm.getRegisteredProviders() });\n  });\n\n  // ── DAG memory endpoints ─────────────────────────────────────────────────\n  app.post(\"/memory/dag/run\", async (_req, reply) => {\n    const memory = getService<{ runDAGPass: (b?: number) => Promise<{ leafSummariesCreated: number; condensedSummariesCreated: number }> }>(\"memory\");\n    if (!memory) return reply.status(503).send({ error: \"Memory not available\" });\n    const result = await memory.runDAGPass(3);\n    return reply.send({ ...result, message: \"DAG pass complete\" });\n  });\n\n  app.get(\"/memory/dag/stats\", async (_req, reply) => {\n    const memory = getService<{ getDAGStats: () => Record<string, number> }>(\"memory\");\n    if (!memory) return reply.status(503).send({ error: \"Memory not available\" });\n    return reply.send(memory.getDAGStats());\n  });\n\n  app.get<{ Params: { id: string } }>(\"/memory/dag/trace/:id\", async (req, reply) => {\n    const memory = getService<{ traceSources: (id: string) => unknown[] }>(\"memory\");\n    if (!memory) return reply.status(503).send({ error: \"Memory not available\" });\n    return reply.send({ chain: memory.traceSources(req.params.id) });\n  });\n\n  // ── Session archive (manual trigger) ──────────────────────────────────────\n  app.post(\"/memory/archive\", async (_req, reply) => {\n    const memory = getService<{ archiveSession: (summarize: boolean) => Promise<void>; getWorkingMemory: () => unknown[] }>(\"memory\");\n    if (!memory) return reply.status(503).send({ error: \"Memory not available\" });\n    const count = memory.getWorkingMemory().length;\n    if (count < 2) return reply.send({ message: \"nothing to archive\", messages: count });\n    await memory.archiveSession(true);\n    return reply.send({ message: \"session archived\", messages: count });\n  });\n  // ── ComfyUI process management + idle auto-shutdown ─────────────────────────\n\n  const COMFYUI_DIR     = \"/mnt/ai/comfyui\";\n  const COMFYUI_PYTHON  = \"/mnt/ai/comfyui-venv/bin/python\";\n  const COMFYUI_URL     = \"http://127.0.0.1:8188\";\n  const IDLE_TIMEOUT_MS = 10 * 60 * 1000; // 10 minutes\n\n  let comfyuiProcess: ReturnType<typeof import(\"node:child_process\").spawn> | null = null;\n  let comfyuiLastActivity = 0;\n  let comfyuiIdleTimer: ReturnType<typeof setInterval> | null = null;\n  let comfyuiStartedAt = 0;\n\n  function resetComfyIdleTimer() {\n    comfyuiLastActivity = Date.now();\n  }\n\n  async function isComfyRunning(): Promise<boolean> {\n    try {\n      const r = await fetch(`${COMFYUI_URL}/system_stats`, { signal: AbortSignal.timeout(2000) });\n      return r.ok;\n    } catch { return false; }\n  }\n\n  async function stopComfyUI(reason: string): Promise<void> {\n    if (comfyuiIdleTimer) { clearInterval(comfyuiIdleTimer); comfyuiIdleTimer = null; }\n    if (comfyuiProcess) {\n      app.log.info(`[comfyui] stopping — reason: ${reason}`);\n      comfyuiProcess.kill(\"SIGTERM\");\n      // Give it 5s to exit gracefully, then SIGKILL\n      setTimeout(() => { if (comfyuiProcess) { comfyuiProcess.kill(\"SIGKILL\"); comfyuiProcess = null; } }, 5000);\n      comfyuiProcess = null;\n    } else {\n      // Process not managed by us — try killing any comfyui on port 8188\n      try {\n        const { execFile: ef } = await import(\"node:child_process\");\n        const { promisify: p } = await import(\"node:util\");\n        const execAsync = p(ef);\n        await execAsync(\"fuser\", [\"-k\", \"8188/tcp\"], { timeout: 5000 }).catch(() => {});\n      } catch { /* best effort */ }\n    }\n\n    // Write receipt\n    const receiptsDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n    const { appendFile: af, mkdir: mk } = await import(\"node:fs/promises\");\n    const { join: jn } = await import(\"node:path\");\n    const { randomUUID: uuid } = await import(\"node:crypto\");\n    await mk(receiptsDir, { recursive: true });\n    const date = new Date().toISOString().slice(0, 10);\n    await af(jn(receiptsDir, `${date}.jsonl`), JSON.stringify({\n      id: uuid(), timestamp: new Date().toISOString(),\n      componentType: \"module-event\", componentName: \"comfyui\",\n      moduleId: \"squidley.integration.comfyui\",\n      reason: `comfyui:auto-shutdown:${reason}`,\n      status: \"success\", surfacedToUser: true,\n      meta: { reason, uptimeMs: comfyuiStartedAt ? Date.now() - comfyuiStartedAt : 0 },\n    }) + \"\\n\", \"utf-8\").catch(() => {});\n\n    comfyuiStartedAt = 0;\n    app.log.info(`[comfyui] stopped — reason: ${reason}`);\n  }\n\n  function startIdleWatcher() {\n    if (comfyuiIdleTimer) clearInterval(comfyuiIdleTimer);\n    resetComfyIdleTimer();\n    comfyuiIdleTimer = setInterval(async () => {\n      if (!comfyuiLastActivity) return;\n      const idle = Date.now() - comfyuiLastActivity;\n      if (idle >= IDLE_TIMEOUT_MS) {\n        await stopComfyUI(\"idle-timeout\");\n      }\n    }, 30_000); // check every 30s\n  }\n\n  async function writeImageGenerationReceipt(meta: { model: string; path: \"cloud\" | \"local\"; costPerImageUsd: number; totalCostUsd: number; prompt: string; intent: string; imageCount: number }) {\n    const receiptsDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n    const { appendFile: af, mkdir: mk } = await import(\"node:fs/promises\");\n    const { join: jn } = await import(\"node:path\");\n    const { randomUUID: uuid } = await import(\"node:crypto\");\n    await mk(receiptsDir, { recursive: true });\n    const date = new Date().toISOString().slice(0, 10);\n    await af(jn(receiptsDir, date + \".jsonl\"), JSON.stringify({\n      id: uuid(),\n      timestamp: new Date().toISOString(),\n      componentType: \"image-generation\",\n      componentName: \"eidolon\",\n      moduleId: \"eidolon\",\n      reason: \"eidolon:image:\" + meta.path,\n      status: \"success\",\n      surfacedToUser: true,\n      meta,\n    }) + \"\\n\", \"utf-8\").catch(() => {});\n  }\n\n  // ── Image generation (MiniMax cloud / ComfyUI local) ───────────────────────\n  app.post(\"/image/generate\", async (req, reply) => {\n    resetComfyIdleTimer();\n    const comfyui = getService<{ generate: (opts: unknown) => Promise<unknown>; isReady: () => Promise<boolean> }>(\"comfyui\");\n    const minimaxImages = getService<{ generate: (opts: { prompt: string; aspectRatio?: string; n?: number; seed?: number; promptOptimizer?: boolean }) => Promise<{ model: string; imageBase64: string[]; imageUrls: string[]; count: number; costPerImageUsd: number; totalCostUsd: number; durationMs: number }> }>(\"minimax-images\");\n    const body = req.body as {\n      prompt: string; negative?: string; intent?: string; feedback?: string;\n      max_iterations?: number; steps?: number; seed?: number; output?: string;\n      use_local_comfy?: boolean; aspect_ratio?: string;\n    };\n    if (!body.prompt) return reply.status(400).send({ ok: false, error: \"prompt required\" });\n\n    const useLocalComfy = body.use_local_comfy === true;\n\n    try {\n      if (useLocalComfy) {\n        if (!comfyui) return reply.status(503).send({ ok: false, error: \"ComfyUI module not available\" });\n        const local = await comfyui.generate({\n          prompt: body.prompt, negative: body.negative, intent: body.intent ?? body.prompt,\n          feedback: body.feedback, maxIterations: body.max_iterations ?? 3,\n          steps: body.steps ?? 20, seed: body.seed, outputPrefix: body.output ?? \"squidley_gen\",\n        }) as {\n          ok: boolean; file: string; finalPrompt: string; intent: string; iterations: Array<{ n: number; prompt: string; file: string; vlDescription: string; qcPass: boolean; qcNotes: string; elapsedMs: number }>; totalIterations: number; qcPassed: boolean; seed: number; error?: string;\n        };\n        resetComfyIdleTimer();\n        const localResult = {\n          ...local,\n          model: \"sdxl\",\n          generationPath: \"local\",\n          costPerImageUsd: 0,\n          totalCostUsd: 0,\n          imageUrl: local.file ? \"/image/output/\" + local.file : \"\",\n          iterations: local.iterations.map(iter => ({ ...iter, imageUrl: \"/image/output/\" + iter.file })),\n        };\n        if (local.ok) {\n          await writeImageGenerationReceipt({ model: \"sdxl\", path: \"local\", costPerImageUsd: 0, totalCostUsd: 0, prompt: body.prompt, intent: body.intent ?? body.prompt, imageCount: 1 });\n        }\n        return reply.send(localResult);\n      }\n\n      if (!minimaxImages) return reply.status(503).send({ ok: false, error: \"MiniMax image service not available\" });\n      const cloud = await minimaxImages.generate({\n        prompt: body.prompt,\n        aspectRatio: body.aspect_ratio ?? \"1:1\",\n        n: 1,\n        ...(typeof body.seed === \"number\" ? { seed: body.seed } : {}),\n        promptOptimizer: true,\n      });\n      const imageUrl = cloud.imageBase64[0] ? \"data:image/png;base64,\" + cloud.imageBase64[0] : (cloud.imageUrls[0] ?? \"\");\n      const cloudResult = {\n        ok: true,\n        file: \"\",\n        imageUrl,\n        finalPrompt: body.prompt,\n        intent: body.intent ?? body.prompt,\n        iterations: [{\n          n: 1,\n          prompt: body.prompt,\n          file: \"\",\n          imageUrl,\n          vlDescription: \"Cloud generation via MiniMax image-01\",\n          qcPass: true,\n          qcNotes: \"Cloud path active — no local ComfyUI feedback loop\",\n          elapsedMs: cloud.durationMs,\n        }],\n        totalIterations: 1,\n        qcPassed: true,\n        seed: body.seed ?? 0,\n        model: cloud.model,\n        generationPath: \"cloud\",\n        costPerImageUsd: cloud.costPerImageUsd,\n        totalCostUsd: cloud.totalCostUsd,\n      };\n      await writeImageGenerationReceipt({ model: cloud.model, path: \"cloud\", costPerImageUsd: cloud.costPerImageUsd, totalCostUsd: cloud.totalCostUsd, prompt: body.prompt, intent: body.intent ?? body.prompt, imageCount: cloud.count });\n      return reply.send(cloudResult);\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  app.get(\"/image/status\", async (_req, reply) => {\n    const running = await isComfyRunning();\n    const idleMs = comfyuiLastActivity ? Date.now() - comfyuiLastActivity : 0;\n    const remainingMs = comfyuiLastActivity ? Math.max(0, IDLE_TIMEOUT_MS - idleMs) : 0;\n    return reply.send({\n      ok: running,\n      status: running ? \"running\" : \"offline\",\n      idleMs: running ? idleMs : 0,\n      idleTimeoutMs: IDLE_TIMEOUT_MS,\n      remainingMs: running ? remainingMs : 0,\n      startedAt: comfyuiStartedAt || null,\n    });\n  });\n\n  app.post(\"/comfyui/start\", async (_req, reply) => {\n    try {\n      // Check if already running\n      if (await isComfyRunning()) {\n        resetComfyIdleTimer();\n        startIdleWatcher();\n        return reply.send({ ok: true, started: true, already_running: true });\n      }\n\n      app.log.info(\"[comfyui] starting process directly...\");\n\n      // Spawn ComfyUI directly — no systemctl needed\n      const { spawn: sp } = await import(\"node:child_process\");\n      const child = sp(COMFYUI_PYTHON, [\"main.py\", \"--listen\", \"127.0.0.1\", \"--port\", \"8188\"], {\n        cwd: COMFYUI_DIR,\n        stdio: [\"ignore\", \"pipe\", \"pipe\"],\n        detached: false,\n        env: { ...process.env, TMPDIR: \"/mnt/ai/tmp\" },\n      });\n\n      comfyuiProcess = child;\n      comfyuiStartedAt = Date.now();\n\n      // Log stdout/stderr\n      child.stdout?.on(\"data\", (chunk: Buffer) => {\n        const line = chunk.toString().trim();\n        if (line) app.log.info(`[comfyui:stdout] ${line}`);\n      });\n      child.stderr?.on(\"data\", (chunk: Buffer) => {\n        const line = chunk.toString().trim();\n        if (line) app.log.warn(`[comfyui:stderr] ${line}`);\n      });\n\n      child.on(\"exit\", (code, signal) => {\n        app.log.info(`[comfyui] process exited — code=${code} signal=${signal}`);\n        comfyuiProcess = null;\n        comfyuiStartedAt = 0;\n        if (comfyuiIdleTimer) { clearInterval(comfyuiIdleTimer); comfyuiIdleTimer = null; }\n      });\n\n      child.on(\"error\", (err) => {\n        app.log.error(`[comfyui] process error: ${err.message}`);\n        comfyuiProcess = null;\n      });\n\n      // Wait up to 30 seconds for health (SDXL model loading is slow)\n      for (let i = 0; i < 30; i++) {\n        await new Promise(r => setTimeout(r, 1000));\n        if (await isComfyRunning()) {\n          startIdleWatcher();\n          app.log.info(`[comfyui] ready after ${i + 1}s`);\n          return reply.send({ ok: true, started: true });\n        }\n      }\n\n      startIdleWatcher(); // Start timer anyway\n      return reply.send({ ok: true, started: true, message: \"Process launched but still loading models — check again shortly\" });\n    } catch (err) {\n      app.log.error(`[comfyui] start failed: ${err instanceof Error ? err.stack : String(err)}`);\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  app.post(\"/comfyui/stop\", async (_req, reply) => {\n    try {\n      await stopComfyUI(\"manual\");\n      return reply.send({ ok: true, stopped: true });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  app.get(\"/image/list\", async (_req, reply) => {\n    const comfyui = getService<{ listImages: () => Promise<string[]> }>(\"comfyui\");\n    if (!comfyui) return reply.status(503).send({ ok: false, error: \"ComfyUI module not available\" });\n    const files = await comfyui.listImages();\n    return reply.send({ ok: true, images: files.map(f => ({ filename: f, url: `/image/output/${f}` })) });\n  });\n\n  app.get<{ Params: { filename: string } }>(\"/image/output/:filename\", async (req, reply) => {\n    const { filename } = req.params;\n    const safe = filename.replace(/[^a-zA-Z0-9_.\\-]/g, \"\");\n    if (!safe.endsWith(\".png\") && !safe.endsWith(\".jpg\") && !safe.endsWith(\".webp\")) {\n      return reply.status(400).send({ ok: false, error: \"Invalid filename\" });\n    }\n    try {\n      const comfyuiUrl = (process.env[\"COMFYUI_URL\"] ?? \"http://127.0.0.1:8188\").replace(/\\/+$/, \"\");\n      const viewResp = await fetch(`${comfyuiUrl}/view?filename=${encodeURIComponent(safe)}`, { signal: AbortSignal.timeout(15_000) });\n      if (!viewResp.ok) return reply.status(404).send({ ok: false, error: \"Image not found\" });\n      const contentType = viewResp.headers.get(\"content-type\") ?? \"image/png\";\n      const data = Buffer.from(await viewResp.arrayBuffer());\n      return reply.type(contentType).send(data);\n    } catch (err) { return reply.status(502).send({ ok: false, error: String(err) }); }\n  });\n\n  // ── Auriga — Video Production Pipeline ───────────────────────────────────\n\n  const auriga = getService<{\n    createSession: (name: string, mode: string, brief: string) => Record<string, unknown>;\n    getSession: (id: string) => Record<string, unknown> | null;\n    listSessions: () => Array<Record<string, unknown>>;\n    updateSession: (id: string, patch: Record<string, unknown>) => Record<string, unknown> | null;\n    deleteSession: (id: string) => boolean;\n    addStage: (sessionId: string, stage: string) => Record<string, unknown>;\n    updateStage: (stageId: string, patch: Record<string, unknown>) => Record<string, unknown> | null;\n    getStages: (sessionId: string) => Array<Record<string, unknown>>;\n    addAsset: (sessionId: string, type: string, filename: string, mimeType: string, archivumId: string | null, metadata: Record<string, unknown>) => Record<string, unknown>;\n    getAssets: (sessionId: string) => Array<Record<string, unknown>>;\n    saveDna: (assetId: string, dna: Record<string, unknown>) => Record<string, unknown>;\n    getDna: (assetId: string) => Record<string, unknown> | null;\n    stages: string[];\n    stageDescriptions: Record<string, string>;\n    ffmpeg: {\n      probe: (filePath: string) => Promise<Record<string, unknown>>;\n    };\n  }>(\"auriga\");\n\n  // Session CRUD\n  app.get(\"/auriga/sessions\", async (_req, reply) => {\n    if (!auriga) return reply.status(503).send({ ok: false, error: \"Auriga not available\" });\n    return reply.send({ ok: true, sessions: auriga.listSessions() });\n  });\n\n  app.post<{ Body: { name: string; mode?: string; brief?: string } }>(\"/auriga/sessions\", async (req, reply) => {\n    if (!auriga) return reply.status(503).send({ ok: false, error: \"Auriga not available\" });\n    const { name, mode = \"video\", brief = \"\" } = req.body ?? {};\n    if (!name) return reply.status(400).send({ ok: false, error: \"name is required\" });\n    const session = auriga.createSession(name, mode,