ader(\"Content-Type\", \"audio/mpeg\")\n            .header(\"X-TTS-Provider\", \"elevenlabs\")\n            .header(\"X-TTS-Voice-Id\", voice_id)\n            .header(\"X-TTS-Duration-Ms\", String(durationMs))\n            .send(audioBuffer);\n        }\n\n        app.log.warn(`[magister:tts] ElevenLabs failed ${res.status}, falling back to Piper`);\n      } catch (err) {\n        app.log.warn(`[magister:tts] ElevenLabs error, falling back to Piper: ${err}`);\n      }\n    }\n\n    // Fallback to Piper\n    try {\n      const { spawn } = await import(\"node:child_process\");\n      const { randomUUID } = await import(\"node:crypto\");\n      const { join } = await import(\"node:path\");\n      const { readFile: rf, unlink, mkdir: mk, appendFile: rAppend } = await import(\"node:fs/promises\");\n\n      const tmpDir = join(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"tmp\");\n      await mk(tmpDir, { recursive: true });\n      const outFile = join(tmpDir, `tts-${randomUUID()}.wav`);\n      const modelPath = `${PIPER_VOICES_DIR}/en_GB-alba-medium.onnx`;\n\n      await new Promise<void>((resolve, reject) => {\n        const proc = spawn(PIPER_BIN, [\"-m\", modelPath, \"-f\", outFile], {\n          stdio: [\"pipe\", \"pipe\", \"pipe\"], timeout: 30_000,\n        });\n        proc.stdin.write(text);\n        proc.stdin.end();\n        let stderr = \"\";\n        proc.stderr.on(\"data\", (d: Buffer) => { stderr += d.toString(); });\n        proc.on(\"close\", (code) => code === 0 ? resolve() : reject(new Error(`Piper fallback exited ${code}: ${stderr}`)));\n        proc.on(\"error\", reject);\n      });\n\n      const audioBuffer = await rf(outFile);\n      unlink(outFile).catch(() => {});\n\n      const receiptsDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n      await mk(receiptsDir, { recursive: true });\n      await rAppend(join(receiptsDir, `${new Date().toISOString().slice(0, 10)}.jsonl`), JSON.stringify({\n        id: randomUUID(), timestamp: new Date().toISOString(),\n        componentType: \"module-event\", componentName: \"magister-tts\",\n        moduleId: \"magister\", reason: \"magister:tts:piper-fallback\",\n        status: \"success\", surfacedToUser: true,\n        meta: { voice: \"en_GB-alba-medium\", characters: text.length, durationMs: Date.now() - start, fallbackFrom: \"elevenlabs\" },\n      }) + \"\\n\", \"utf-8\").catch(() => {});\n\n      return reply\n        .header(\"Content-Type\", \"audio/wav\")\n        .header(\"X-TTS-Provider\", \"piper-fallback\")\n        .send(audioBuffer);\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: `All TTS providers failed: ${String(err)}` });\n    }\n  });\n\n  // ── Planner ───────────────────────────────────────────────────────────────\n  app.post(\"/planner/chat\", async (req, reply) => {\n    const body = req.body as { message: string; history: Array<{ role: string; content: string }> };\n    const pm = getService<{ complete: (opts: unknown) => Promise<{ text: string }> }>(\"provider-manager\");\n    if (!pm) return reply.status(503).send({ error: \"Provider not available\" });\n    const messages = [\n      { role: \"system\", content: \"You are Squidley's Socratic planner. Ask ONE focused clarifying question at a time. Keep questions short. After 2-3 exchanges you will have enough to crystallize a plan. Do NOT write code.\" },\n      ...body.history,\n      { role: \"user\", content: body.message },\n    ];\n    const result = await pm.complete({ tier: \"plan\", messages, reason: \"planner:interview\", stream: false }) as { text: string };\n    return reply.send({ reply: result.text });\n  });\n\n  app.post(\"/planner/crystallize\", async (req, reply) => {\n    const body = req.body as { history: Array<{ role: string; content: string }> };\n    const pm = getService<{ complete: (opts: unknown) => Promise<{ text: string }> }>(\"provider-manager\");\n    if (!pm) return reply.status(503).send({ error: \"Provider not available\" });\n    const messages = [\n      { role: \"system\", content: \"Produce a concise build plan with: ## Goal, ## Target Files, ## Changes (bullets), ## Constraints. Be specific.\" },\n      ...body.history,\n      { role: \"user\", content: \"Crystallize this into a build plan.\" },\n    ];\n    const result = await pm.complete({ tier: \"plan\", messages, reason: \"planner:crystallize\", stream: false }) as { text: string };\n    return reply.send({ plan: result.text });\n  });\n\n  // ── Archivum — universal ingestion (images + documents) ──────────────────\n\n  const IMAGE_MIMES = new Set([\"image/jpeg\",\"image/png\",\"image/gif\",\"image/webp\",\"image/bmp\",\"image/tiff\",\"image/svg+xml\",\"image/heic\",\"image/heif\"]);\n  const DOCUMENT_MIMES = new Set([\n    \"application/pdf\",\n    \"application/vnd.openxmlformats-officedocument.wordprocessingml.document\",\n    \"application/msword\",\n    \"text/plain\",\n    \"text/markdown\",\n    \"text/x-markdown\",\n    \"application/octet-stream\", // browsers often send this for docx/pdf — fall through to ext check\n  ]);\n  const DOCUMENT_EXTS = new Set([\"pdf\",\"docx\",\"doc\",\"txt\",\"md\",\"markdown\"]);\n  const MAX_INGEST_BYTES = 20 * 1024 * 1024;\n  const BASE64_RE = /^(?:[A-Za-z0-9+/]{4})*(?:[A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/;\n\n  function normalizeBase64Payload(base64: string): string {\n    const normalized = (base64 ?? \"\").trim().replace(/\\s+/g, \"\");\n    if (!normalized) throw new Error(\"base64 required\");\n    if (!BASE64_RE.test(normalized)) throw new Error(\"invalid base64 payload\");\n    return normalized;\n  }\n\n  function estimateDecodedBytes(base64: string): number {\n    const padding = base64.endsWith(\"==\") ? 2 : base64.endsWith(\"=\") ? 1 : 0;\n    return Math.floor((base64.length * 3) / 4) - padding;\n  }\n\n  function decodeBase64Payload(base64: string): Buffer {\n    const normalized = normalizeBase64Payload(base64);\n    const estimatedBytes = estimateDecodedBytes(normalized);\n    if (estimatedBytes > MAX_INGEST_BYTES) {\n      throw new Error(`file exceeds ${MAX_INGEST_BYTES / (1024 * 1024)}MB limit`);\n    }\n    const buf = Buffer.from(normalized, \"base64\");\n    if (buf.length === 0) throw new Error(\"empty buffer — file not received or base64 was empty\");\n    if (buf.length > MAX_INGEST_BYTES) {\n      throw new Error(`file exceeds ${MAX_INGEST_BYTES / (1024 * 1024)}MB limit`);\n    }\n    return buf;\n  }\n\n  function classifyFile(mimeType: string, filename?: string): \"image\" | \"document\" | \"unknown\" {\n    const mime  = (mimeType ?? \"\").trim().toLowerCase().split(\";\")[0]!.trim();\n    const ext   = (filename ?? \"\").split(\".\").pop()?.toLowerCase() ?? \"\";\n\n    if (mime.startsWith(\"image/\") || IMAGE_MIMES.has(mime)) return \"image\";\n    if (DOCUMENT_EXTS.has(ext)) return \"document\"; // ext wins over ambiguous MIME\n    if (DOCUMENT_MIMES.has(mime) && mime !== \"application/octet-stream\") return \"document\";\n    return \"unknown\";\n  }\n\n  async function extractDocument(\n    base64: string,\n    mimeType: string,\n    filename?: string,\n    log?: { info: (o: object) => void; error: (o: object) => void }\n  ): Promise<{ text: string; pageCount?: number; wordCount: number }> {\n    const buf = decodeBase64Payload(base64);\n    const ext = (filename ?? \"\").split(\".\").pop()?.toLowerCase();\n\n    log?.info({ event: \"archivum:extract-document-start\", mimeType, ext, filename, bufferBytes: buf?.length ?? \"undefined\" });\n\n\n    if (mimeType === \"application/pdf\" || ext === \"pdf\") {\n      try {\n        const pdfParseUnknown = await import(\"pdf-parse\") as unknown;\n        const pdfParse = typeof pdfParseUnknown === \"function\"\n          ? pdfParseUnknown as (input: Buffer) => Promise<{ text?: string; numpages?: number }>\n          : (pdfParseUnknown as { default?: (input: Buffer) => Promise<{ text?: string; numpages?: number }> }).default;\n        if (typeof pdfParse !== \"function\") throw new Error(\"pdf-parse export not callable\");\n        const data = await pdfParse(buf);\n        const text = (data.text ?? \"\").trim();\n        const wordCount = text.length > 0 ? text.split(/\\s+/).filter(Boolean).length : 0;\n        log?.info({ event: \"archivum:pdf-ok\", pages: data.numpages, words: wordCount });\n        return data.numpages != null ? { text, pageCount: data.numpages, wordCount } : { text, wordCount };\n      } catch (err) {\n        log?.error({ event: \"archivum:pdf-failed\", error: String(err), stack: (err as Error).stack });\n        throw new Error(`pdf-parse failed: ${String(err)}`);\n      }\n    }\n\n    if (mimeType === \"application/vnd.openxmlformats-officedocument.wordprocessingml.document\" || ext === \"docx\") {\n      try {\n        const mammoth = await import(\"mammoth\");\n        log?.info({ event: \"archivum:mammoth-start\", bufferBytes: buf.length });\n        const result = await mammoth.extractRawText({ buffer: buf });\n        if (result.messages?.length) {\n          log?.info({ event: \"archivum:mammoth-messages\", messages: result.messages });\n        }\n        const text = (result?.value ?? \"\").trim();\n        const wordCount = text.length > 0 ? text.split(/\\s+/).filter(Boolean).length : 0;\n        log?.info({ event: \"archivum:docx-ok\", words: wordCount });\n        return { text, wordCount };\n      } catch (err) {\n        log?.error({ event: \"archivum:docx-failed\", error: String(err), stack: (err as Error).stack });\n        throw new Error(`mammoth failed: ${String(err)}`);\n      }\n    }\n\n    // TXT / MD — plain read\n    const text = (buf.toString(\"utf-8\") ?? \"\").trim();\n    const wordCount = text.length > 0 ? text.split(/\\s+/).filter(Boolean).length : 0;\n    log?.info({ event: \"archivum:text-ok\", words: wordCount });\n    return { text, wordCount };\n  }\n\n  async function purgeExpiredArchivumEntries() {\n    const uploadDir = process.env[\"ARCHIVUM_UPLOAD_DIR\"] ?? (process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd()) + \"/state/uploads\";\n    const { readdir, readFile, unlink } = await import(\"node:fs/promises\");\n    const { join } = await import(\"node:path\");\n    const now = Date.now();\n    const files = await readdir(uploadDir).catch(() => [] as string[]);\n    for (const jsonFile of files.filter((file) => file.startsWith(\"arch-\") && file.endsWith(\".json\"))) {\n      try {\n        const jsonPath = join(uploadDir, jsonFile);\n        const raw = await readFile(jsonPath, \"utf-8\");\n        const entry = JSON.parse(raw) as { id?: string; expiresAt?: number };\n        if (!entry.expiresAt || entry.expiresAt > now) continue;\n        const base = jsonFile.replace(/\\.json$/, \"\");\n        const related = files.filter((file) => file === jsonFile || (file.startsWith(base + \".\") && !file.endsWith(\".json\")));\n        for (const file of related) await unlink(join(uploadDir, file)).catch(() => {});\n      } catch {\n        /* ignore malformed archivum entry */\n      }\n    }\n  }\n\n  app.post(\"/archivum/ingest\", async (req, reply) => {\n    const arch = getService<{\n      extract: (b64: string, mime: string, hint?: string) => Promise<unknown>;\n      buildContext: (extraction: unknown, filename?: string) => string;\n      save: (b64: string, mime: string, extraction: unknown, hint?: string, options?: { originalFilename?: string; section?: string; source?: string; retention?: \"temporary\" | \"permanent\"; tags?: string[]; expiresAt?: number }) => Promise<unknown>;\n    }>(\"archivum\");\n    if (!arch) return reply.status(503).send({ error: \"Archivum not available\" });\n    const body = req.body as { base64: string; mimeType: string; hint?: string; filename?: string; save?: boolean; cloud?: boolean; section?: string; source?: string; retention?: \"temporary\" | \"permanent\"; ttlHours?: number; tags?: string[] };\n    await purgeExpiredArchivumEntries();\n    req.log.info({ event: \"archivum:ingest-incoming\", filename: body.filename, mimeType: body.mimeType, base64Len: body.base64?.length ?? \"undefined\", hasBase64: !!body.base64 });\n    if (!body.base64) return reply.status(400).send({ error: \"base64 required\" });\n\n    let normalizedBase64: string;\n    try {\n      normalizedBase64 = normalizeBase64Payload(body.base64);\n    } catch (err) {\n      return reply.status(400).send({ ok: false, error: err instanceof Error ? err.message : String(err) });\n    }\n\n    const estimatedBytes = estimateDecodedBytes(normalizedBase64);\n    if (estimatedBytes > MAX_INGEST_BYTES) {\n      return reply.status(413).send({ ok: false, error: `file exceeds ${MAX_INGEST_BYTES / (1024 * 1024)}MB limit` });\n    }\n\n    const fileClass = classifyFile(body.mimeType ?? \"\", body.filename);\n    req.log.info({ event: \"archivum:ingest-classify\", mimeType: body.mimeType, filename: body.filename, fileClass });\n\n    try {\n      let extraction: unknown;\n\n      if (fileClass === \"document\") {\n        // ── Document path — text extraction, no vision model\n        const doc = await extractDocument(normalizedBase64, body.mimeType ?? \"text/plain\", body.filename, req.log);\n        extraction = {\n          type: \"document\",\n          filename: body.filename,\n          mimeType: body.mimeType,\n          text: doc.text,\n          pageCount: doc.pageCount,\n          wordCount: doc.wordCount,\n          extractedAt: new Date().toISOString(),\n          // ExtractionResult compat — buildChatContext iterates these\n          sourceType: \"document\",\n          summary: doc.text.slice(0, 300).trim(),\n          topics: [],\n          actionable: [],\n          relevantTo: [],\n          confidence: 1,\n          model: \"text-extraction\",\n          durationMs: 0,\n        };\n        req.log.info({ event: \"archivum:ingest-document\", filename: body.filename, mimeType: body.mimeType, wordCount: doc.wordCount });\n      } else if (fileClass === \"unknown\") {\n        return reply.status(400).send({ ok: false, error: `unsupported file type: ${body.mimeType ?? \"unknown\"} (${body.filename ?? \"no filename\"})` });\n      } else {\n        // ── Image path — existing vision pipeline unchanged\n        const cloudArch = arch as typeof arch & { extractCloud?: typeof arch.extract };\n        extraction = body.cloud && cloudArch.extractCloud\n          ? await cloudArch.extractCloud(normalizedBase64, body.mimeType ?? \"image/png\", body.hint)\n          : await arch.extract(normalizedBase64, body.mimeType ?? \"image/png\", body.hint);\n        req.log.info({ event: \"archivum:ingest-image\", filename: body.filename, mimeType: body.mimeType });\n      }\n\n      const context = arch.buildContext(extraction, body.filename);\n      let entry = null;\n      if (body.save !== false) {\n        entry = await arch.save(normalizedBase64, body.mimeType ?? \"application/octet-stream\", extraction, body.hint, {\n          ...(body.filename ? { originalFilename: body.filename } : {}),\n          ...(body.section ? { section: body.section } : {}),\n          ...(body.source ? { source: body.source } : {}),\n          ...(body.retention ? { retention: body.retention } : {}),\n          ...(body.tags?.length ? { tags: body.tags } : {}),\n          ...(body.ttlHours && body.ttlHours > 0 ? { expiresAt: Date.now() + (body.ttlHours * 60 * 60 * 1000) } : {}),\n        });\n      }\n      const savedEntry = entry as { id?: string; filename?: string; originalFilename?: string; section?: string; source?: string; retention?: \"temporary\" | \"permanent\"; expiresAt?: number } | null;\n      return reply.send({\n        ok: true,\n        extraction,\n        context,\n        entryId: savedEntry?.id,\n        ...(savedEntry ? {\n          entry: {\n            id: savedEntry.id,\n            filename: savedEntry.filename,\n            originalFilename: savedEntry.originalFilename,\n            section: savedEntry.section,\n            source: savedEntry.source,\n            retention: savedEntry.retention,\n            expiresAt: savedEntry.expiresAt,\n          },\n        } : {}),\n      });\n    } catch (err) {\n      const message = err instanceof Error ? err.message : String(err);\n      const stack   = err instanceof Error ? err.stack : undefined;\n      req.log.error({ event: \"archivum:ingest-failed\", mimeType: (req.body as { mimeType?: string }).mimeType, filename: (req.body as { filename?: string }).filename, error: message, stack });\n      return reply.status(500).send({ ok: false, error: message });\n    }\n  });\n\n  app.get(\"/archivum/entries\", async (req, reply) => {\n    const uploadDir = process.env[\"ARCHIVUM_UPLOAD_DIR\"] ?? (process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd()) + \"/state/uploads\";\n    try {\n      await purgeExpiredArchivumEntries();\n      const { readdir, readFile } = await import(\"node:fs/promises\");\n      const { join } = await import(\"node:path\");\n      const files = await readdir(uploadDir);\n      const jsonFiles = files.filter(f => f.endsWith(\".json\"));\n      const entries = await Promise.all(\n        jsonFiles.map(async f => {\n          try {\n            const raw = await readFile(join(uploadDir, f), \"utf-8\");\n            return JSON.parse(raw);\n          } catch { return null; }\n        })\n      );\n      const section = String((req.query as { section?: string } | undefined)?.section ?? \"\").trim();\n      const valid = entries.filter(Boolean).filter((entry) => !section || entry.section === section).sort((a, b) => (b.createdAt ?? 0) - (a.createdAt ?? 0));\n      return reply.send({ ok: true, entries: valid });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, entries: [], error: String(err) });\n    }\n  });\n\n  app.delete<{ Params: { id: string } }>(\"/archivum/entries/:id\", async (req, reply) => {\n    const uploadDir = process.env[\"ARCHIVUM_UPLOAD_DIR\"] ?? (process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd()) + \"/state/uploads\";\n    const { id } = req.params;\n    const safe = id.replace(/[^a-zA-Z0-9_\\-]/g, \"\");\n    if (!safe) return reply.status(400).send({ ok: false, error: \"Invalid id\" });\n    try {\n      const { readdir, unlink } = await import(\"node:fs/promises\");\n      const { join } = await import(\"node:path\");\n      const files = await readdir(uploadDir);\n      const toDelete = files.filter((f) => f === safe + \".json\" || f.startsWith(safe + \".\"));\n      for (const f of toDelete) await unlink(join(uploadDir, f));\n      return reply.send({ ok: true, deleted: toDelete.length });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Screenshot — capture desktop/window, optionally save to Archivum ──\n\n  app.post<{ Body: { mode?: \"desktop\" | \"window\" | \"region\"; monitor?: number; save?: boolean; analyze?: boolean; hint?: string } }>(\"/screenshot\", async (req, reply) => {\n    const { mode = \"desktop\", monitor = 0, save = false, analyze = false, hint } = req.body ?? {};\n\n    try {\n      const { execFile: ef } = await import(\"node:child_process\");\n      const { promisify: p } = await import(\"node:util\");\n      const { readFile: rf, unlink: ul } = await import(\"node:fs/promises\");\n      const execAsync = p(ef);\n\n      const timestamp = new Date().toISOString().replace(/[:.]/g, \"-\").slice(0, 19);\n      const tmpNonce = Math.random().toString(36).slice(2, 8);\n      const tmpPath = `/tmp/squidley-screenshot-${timestamp}-${tmpNonce}.png`;\n\n      // Use Python + Pillow for capture — already proven working on Mushin\n      const pyScript = mode === \"window\"\n        // Active window capture via xdotool + Pillow crop (if xdotool available)\n        ? `\nimport subprocess, sys\ntry:\n    wid = subprocess.check_output([\"xdotool\", \"getactivewindow\"], timeout=3).decode().strip()\n    geom = subprocess.check_output([\"xdotool\", \"getwindowgeometry\", \"--shell\", wid], timeout=3).decode()\n    vals = {}\n    for line in geom.strip().split(\"\\\\n\"):\n        k, v = line.split(\"=\")\n        vals[k] = int(v)\n    from PIL import ImageGrab\n    img = ImageGrab.grab(bbox=(vals[\"X\"], vals[\"Y\"], vals[\"X\"]+vals[\"WIDTH\"], vals[\"Y\"]+vals[\"HEIGHT\"]))\n    img.save(\"${tmpPath}\")\n    print(f\"{img.size[0]}x{img.size[1]}\")\nexcept Exception:\n    from PIL import ImageGrab\n    img = ImageGrab.grab()\n    img.save(\"${tmpPath}\")\n    print(f\"{img.size[0]}x{img.size[1]}\")\n`\n        : monitor === 0\n          // Left monitor (first 2560px) or full desktop\n          ? `\nfrom PIL import ImageGrab\nimg = ImageGrab.grab()\n# If multi-monitor, crop to left monitor\nif img.size[0] > 2560:\n    img = img.crop((0, 0, 2560, img.size[1]))\nimg.save(\"${tmpPath}\")\nprint(f\"{img.size[0]}x{img.size[1]}\")\n`\n          // Right monitor\n          : `\nfrom PIL import ImageGrab\nimg = ImageGrab.grab()\nif img.size[0] > 2560:\n    img = img.crop((2560, 0, img.size[0], img.size[1]))\nelse:\n    pass  # single monitor — capture all\nimg.save(\"${tmpPath}\")\nprint(f\"{img.size[0]}x{img.size[1]}\")\n`;\n\n      const { stdout: sizeOut } = await execAsync(\"python3\", [\"-c\", pyScript], {\n        timeout: 10_000,\n        env: { ...process.env, DISPLAY: process.env[\"DISPLAY\"] ?? \":1\" },\n      });\n\n      const resolution = sizeOut.trim();\n      const imgBuffer = await rf(tmpPath);\n      const base64 = imgBuffer.toString(\"base64\");\n\n      // Clean up temp file\n      void ul(tmpPath).catch(() => {});\n\n      const screenshotHint = hint ?? `Screenshot ${mode} ${timestamp}`;\n      const screenshotFilename = `screenshot-${timestamp}.png`;\n      const arch = getService<{\n        extract: (b64: string, mime: string, hint?: string) => Promise<Record<string, unknown>>;\n        save?: (b64: string, mime: string, extraction: Record<string, unknown>, hint?: string, options?: { originalFilename?: string; source?: string }) => Promise<{ id?: string } | null>;\n      }>(\"archivum\");\n\n      // Vision analysis can run independently of whether the screenshot is persisted.\n      let extraction: Record<string, unknown> | null = null;\n      let analysisSucceeded = false;\n      if (analyze && arch) {\n        try {\n          extraction = await arch.extract(base64, \"image/png\", screenshotHint);\n          analysisSucceeded = true;\n          req.log.info({ event: \"screenshot:vision-analyzed\" });\n        } catch (archErr) {\n          req.log.warn({ event: \"screenshot:vision-failed\", error: String(archErr) });\n        }\n      }\n\n      if (!extraction) {\n        extraction = {\n          text: \"Screenshot captured and stored without visual analysis.\",\n          topics: [],\n          sourceType: \"screenshot\",\n          summary: \"Screenshot captured and stored without visual analysis.\",\n          actionable: [],\n          relevantTo: [],\n          confidence: 0.1,\n          model: \"archivum:screenshot-fallback\",\n          durationMs: 0,\n        };\n      }\n\n      let saved = false;\n      let entryId: string | null = null;\n      if (save) {\n        try {\n          if (arch?.save) {\n            const entry = await arch.save(base64, \"image/png\", extraction, screenshotHint, {\n              originalFilename: screenshotFilename,\n              source: \"screenshot\",\n            });\n            entryId = entry?.id ?? null;\n            saved = !!entryId;\n          }\n          req.log.info({ event: \"screenshot:saved\", id: entryId, analyzed: analysisSucceeded });\n        } catch (saveErr) {\n          req.log.warn({ event: \"screenshot:save-failed\", error: String(saveErr) });\n        }\n      }\n\n      return reply.send({\n        ok: true,\n        resolution,\n        mode,\n        monitor,\n        saved,\n        ...(entryId ? { entryId } : {}),\n        analyzed: analysisSucceeded,\n        extraction: extraction ?? null,\n        base64: base64.slice(0, 100) + \"...\",\n        sizeKB: Math.round(imgBuffer.length / 1024),\n        timestamp,\n      });\n    } catch (err) {\n      req.log.error({ event: \"screenshot:failed\", error: String(err) });\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Archivum — paste text directly ────────────────────────────────────\n  app.post<{ Body: { title: string; content: string; tags?: string[]; category?: string } }>(\"/archivum/paste\", async (req, reply) => {\n    const { title, content, tags, category } = req.body;\n    if (!title?.trim() || !content?.trim()) {\n      return reply.status(400).send({ ok: false, error: \"title and content required\" });\n    }\n    try {\n      const allTags = [...(tags ?? [])];\n      if (category && !allTags.includes(category)) allTags.push(category);\n\n      const entry = await saveTextNote({ title: title.trim(), content: content.trim(), tags: allTags });\n\n      // Receipt\n      const { randomUUID: rid } = await import(\"node:crypto\");\n      const { appendFile: af } = await import(\"node:fs/promises\");\n      const { join: pj } = await import(\"node:path\");\n      const receiptsDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n      const date = new Date().toISOString().slice(0, 10);\n      await af(pj(receiptsDir, `${date}.jsonl`), JSON.stringify({\n        id: rid(), timestamp: new Date().toISOString(),\n        componentType: \"archivum:write\", componentName: \"archivum\",\n        moduleId: \"squidley.integration.archivum\", reason: \"archivum:text-paste\",\n        status: \"success\", surfacedToUser: true,\n        meta: { entryId: entry.id, title, source: \"paste\", tags: allTags },\n      }) + \"\\n\", \"utf-8\").catch(() => {});\n\n      req.log.info({ event: \"archivum:paste-saved\", id: entry.id, title });\n      return reply.status(201).send({ ok: true, entry: { id: entry.id, title } });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Archivum — conversation import ──────────────────────────────────────\n  const TAG_RULES: Array<{ keywords: string[]; tag: string }> = [\n    { keywords: [\"squidley\", \"colloquium\", \"symposium\", \"archivum\"], tag: \"squidley\" },\n    { keywords: [\"krakzen\", \"adversarial\", \"injection\"], tag: \"krakzen\" },\n    { keywords: [\"forax\", \"benchmark\", \"local model\", \"gguf\"], tag: \"forax\" },\n    { keywords: [\"atlantis\", \"realm\", \"rpg\", \"dungeon\"], tag: \"atlantis\" },\n    { keywords: [\"architecture\", \"design pattern\", \"module\"], tag: \"architecture\" },\n    { keywords: [\"portfolio\", \"resume\", \"career\", \"cursus\"], tag: \"portfolio\" },\n    { keywords: [\"certif\", \"comptia\", \"security+\", \"a+\"], tag: \"certifications\" },\n    { keywords: [\"python\", \"typescript\", \"grimoire\", \"code review\"], tag: \"development\" },\n    { keywords: [\"claude\", \"gpt\", \"qwen\", \"mimo\", \"ollama\", \"openrouter\"], tag: \"models\" },\n    { keywords: [\"squirrel\", \"tangent\"], tag: \"squirrels\" },\n    { keywords: [\"security\", \"red team\", \"penetration\"], tag: \"security\" },\n    { keywords: [\"velum\", \"privacy\", \"pii\"], tag: \"privacy\" },\n    { keywords: [\"crucible\", \"benchmark\", \"scoring\"], tag: \"benchmarking\" },\n  ];\n\n  function autoTag(text: string): string[] {\n    const lower = text.toLowerCase();\n    const tags = new Set<string>();\n    for (const rule of TAG_RULES) {\n      if (rule.keywords.some(kw => lower.includes(kw))) tags.add(rule.tag);\n    }\n    return Array.from(tags);\n  }\n\n  interface ChatGPTConversation {\n    title?: string;\n    create_time?: number;\n    mapping?: Record<string, { message?: { author?: { role?: string }; content?: { parts?: string[] }; create_time?: number } }>;\n    // Flat format\n    messages?: Array<{ author?: { role?: string }; content?: { parts?: string[] }; create_time?: number; role?: string; text?: string }>;\n  }\n\n  interface ParsedConversation {\n    title: string; date: string; content: string;\n    message_count: number; word_count: number;\n  }\n\n  function parseChatGPTConversation(conv: ChatGPTConversation): ParsedConversation | null {\n    let msgs: Array<{ role: string; text: string }> = [];\n\n    // Mapping format (full export)\n    if (conv.mapping) {\n      const entries = Object.values(conv.mapping)\n        .filter(e => e.message?.content?.parts?.length)\n        .sort((a, b) => (a.message?.create_time ?? 0) - (b.message?.create_time ?? 0));\n      msgs = entries.map(e => ({\n        role: e.message!.author?.role ?? \"unknown\",\n        text: (e.message!.content!.parts ?? []).join(\"\\n\"),\n      })).filter(m => m.role === \"user\" || m.role === \"assistant\");\n    }\n    // Flat messages array\n    else if (conv.messages) {\n      msgs = conv.messages.map(m => ({\n        role: m.author?.role ?? m.role ?? \"unknown\",\n        text: (m.content?.parts ?? [m.text ?? \"\"]).join(\"\\n\"),\n      })).filter(m => (m.role === \"user\" || m.role === \"assistant\") && m.text.trim());\n    }\n\n    if (msgs.length === 0) return null;\n\n    const title = conv.title ?? msgs[0]?.text.slice(0, 60) ?? \"Untitled\";\n    const date = conv.create_time ? new Date(conv.create_time * 1000).toISOString().slice(0, 10) : new Date().toISOString().slice(0, 10);\n    const content = msgs.map(m => `${m.role === \"user\" ? \"User\" : \"Squidley\"}: ${m.text}`).join(\"\\n\\n\");\n\n    return { title, date, content, message_count: msgs.length, word_count: content.split(/\\s+/).length };\n  }\n\n  function parseClaudeExport(text: string): ParsedConversation[] {\n    // Claude exports are typically plain text with \"Human:\" and \"Assistant:\" markers\n    // Or JSON with conversations array\n    try {\n      const parsed = JSON.parse(text);\n      if (Array.isArray(parsed)) {\n        return parsed.map((conv: { name?: string; title?: string; created_at?: string; chat_messages?: Array<{ sender?: string; text?: string }> }) => {\n          const title = conv.name ?? conv.title ?? \"Claude conversation\";\n          const date = conv.created_at ? new Date(conv.created_at).toISOString().slice(0, 10) : new Date().toISOString().slice(0, 10);\n          const content = (conv.chat_messages ?? []).map(m => `${m.sender === \"human\" ? \"User\" : \"Squidley\"}: ${m.text}`).join(\"\\n\\n\");\n          return { title, date, content, message_count: (conv.chat_messages ?? []).length, word_count: content.split(/\\s+/).length };\n        }).filter(c => c.content.length > 0);\n      }\n    } catch { /* not JSON — try plain text */ }\n\n    // Plain text: split on \"Human:\" markers\n    const convos: ParsedConversation[] = [];\n    const blocks = text.split(/(?=^Human:)/m).filter(b => b.trim());\n    for (const block of blocks) {\n      const firstLine = block.split(\"\\n\")[0]?.replace(\"Human:\", \"\").trim() ?? \"\";\n      const content = block.trim().replace(/^Human:/gm, \"User:\").replace(/^Assistant:/gm, \"Squidley:\");\n      convos.push({\n        title: firstLine.slice(0, 60) || \"Claude conversation\",\n        date: new Date().toISOString().slice(0, 10),\n        content,\n        message_count: (content.match(/^(User|Squidley):/gm) ?? []).length,\n        word_count: content.split(/\\s+/).length,\n      });\n    }\n    return convos;\n  }\n\n  app.post<{ Body: { content: string; source?: \"chatgpt\" | \"claude\"; filename?: string; generateSummaries?: boolean } }>(\"/archivum/import-conversations\", async (req, reply) => {\n    const { content, filename, generateSummaries = false } = req.body;\n    if (!content) return reply.status(400).send({ ok: false, error: \"content required\" });\n\n    // Auto-detect format\n    let source: \"chatgpt\" | \"claude\" = req.body.source ?? \"claude\";\n    if (!req.body.source) {\n      try {\n        const parsed = JSON.parse(content);\n        if (Array.isArray(parsed) && parsed.length > 0 && (parsed[0].mapping || parsed[0].messages)) {\n          source = \"chatgpt\";\n        }\n      } catch { source = \"claude\"; }\n    }\n\n    const conversations: ParsedConversation[] = [];\n\n    try {\n      if (source === \"chatgpt\") {\n        const parsed = JSON.parse(content) as ChatGPTConversation[];\n        if (!Array.isArray(parsed)) return reply.status(400).send({ ok: false, error: \"Expected JSON array of conversations\" });\n        for (const conv of parsed) {\n          const result = parseChatGPTConversation(conv);\n          if (result) conversations.push(result);\n        }\n      } else {\n        conversations.push(...parseClaudeExport(content));\n      }\n    } catch (err) {\n      return reply.status(400).send({ ok: false, error: `Failed to parse ${source} export: ${String(err).slice(0, 200)}` });\n    }\n\n    if (conversations.length === 0) {\n      return reply.status(400).send({ ok: false, error: \"No conversations found in export\" });\n    }\n\n    // Load existing entries for duplicate detection\n    const { readdir: rdDir, readFile: rdFile } = await import(\"node:fs/promises\");\n    const { join: djn } = await import(\"node:path\");\n    const uploadDir = process.env[\"ARCHIVUM_UPLOAD_DIR\"] ?? (process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd()) + \"/state/uploads\";\n    const existingTitles = new Set<string>();\n    try {\n      const files = await rdDir(uploadDir);\n      for (const f of files.filter(f => f.endsWith(\".json\"))) {\n        try {\n          const raw = await rdFile(djn(uploadDir, f), \"utf-8\");\n          const entry = JSON.parse(raw) as { filename?: string; extraction?: { topics?: string[] } };\n          if (entry.extraction?.topics?.includes(\"conversation-history\")) {\n            existingTitles.add(entry.filename ?? \"\");\n          }\n        } catch { /* skip */ }\n      }\n    } catch { /* uploads dir may not exist yet */ }\n\n    // Process in chunks with duplicate detection\n    const results: Array<{ id: string; title: string; tags: string[] }> = [];\n    const tagCounts: Record<string, number> = {};\n    let skipped = 0;\n    const CHUNK_SIZE = 10;\n\n    // Optional: get provider-manager for summary generation\n    const pm = generateSummaries ? getService<{ complete: (opts: unknown) => Promise<{ text: string }> }>(\"provider-manager\") : null;\n\n    for (let i = 0; i < conversations.length; i += CHUNK_SIZE) {\n      const chunk = conversations.slice(i, i + CHUNK_SIZE);\n      for (const conv of chunk) {\n        // Duplicate detection: skip if title already exists in conversation-history entries\n        if (existingTitles.has(conv.title)) {\n          skipped++;\n          continue;\n        }\n\n        const tags = [...autoTag(conv.content), \"conversation-history\", `${source}-export`, conv.date];\n        // Flag memoria candidates\n        const memoriaCandidate = tags.some(t => [\"squidley\", \"krakzen\", \"forax\", \"architecture\"].includes(t));\n        if (memoriaCandidate) tags.push(\"memoria-candidate\");\n\n        // Optional AI summary\n        let contentWithSummary = conv.content;\n        if (pm && conv.word_count > 50) {\n          try {\n            const summaryResult = await pm.complete({\n              tier: \"chat\", stream: false, maxTokens: 150,\n              messages: [{ role: \"user\", content: `Summarize this conversation in 2-3 sentences. Focus on decisions made, things built, and key topics:\\n\\n${conv.content.slice(0, 3000)}` }],\n              reason: \"archivum:conversation-import-summary\",\n              meta: { source: \"conversation-import\" },\n            });\n            contentWithSummary = `## Summary\\n${summaryResult.text}\\n\\n---\\n\\n${conv.content}`;\n          } catch { /* summary failed — save without it */ }\n        }\n\n        try {\n          const entry = await saveTextNote({ title: conv.title, content: contentWithSummary, tags });\n          existingTitles.add(conv.title); // prevent dupes within same batch\n          results.push({ id: entry.id, title: conv.title, tags });\n          for (const t of tags) tagCounts[t] = (tagCounts[t] ?? 0) + 1;\n        } catch { /* skip failed entries */ }\n      }\n    }\n\n    // Single receipt for the batch\n    const { randomUUID: rid } = await import(\"node:crypto\");\n    const { appendFile: af } = await import(\"node:fs/promises\");\n    const { join: pj } = await import(\"node:path\");\n    const receiptsDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n    const date = new Date().toISOString().slice(0, 10);\n    const receiptId = rid();\n    await af(pj(receiptsDir, `${date}.jsonl`), JSON.stringify({\n      id: receiptId, timestamp: new Date().toISOString(),\n      componentType: \"archivum:write\", componentName: \"archivum\",\n      moduleId: \"squidley.integration.archivum\", reason: \"archivum:conversation-import\",\n      status: \"success\", surfacedToUser: true,\n      meta: { source, filename, totalConversations: conversations.length, imported: results.length, skipped, tagCounts, generateSummaries },\n    }) + \"\\n\", \"utf-8\").catch(() => {});\n\n    req.log.info({ event: \"archivum:conversations-imported\", source, total: conversations.length, imported: results.length, skipped });\n\n    const topTags = Object.entries(tagCounts)\n      .filter(([k]) => ![\"conversation-history\", `${source}-export`, \"memoria-candidate\"].includes(k) && !k.match(/^\\d{4}/))\n      .sort((a, b) => b[1] - a[1]);\n\n    return reply.send({\n      ok: true,\n      imported: results.length,\n      skipped,\n      total: conversations.length,\n      source,\n      tagCounts,\n      receipt_id: receiptId,\n      entry_ids: results.map(r => r.id),\n      summary: `Imported ${results.length} conversations from ${source === \"chatgpt\" ? \"ChatGPT\" : \"Claude\"}.${\n        skipped > 0 ? ` ${skipped} duplicates skipped.` : \"\"\n      }${topTags.map(([k, v]) => ` ${v} tagged ${k}`).join(\",\")}`,\n    });\n  });\n\n  // ── Forge — remote build terminal ────────────────────────────────────────\n\n  // Command whitelist — no raw shell\n  const FORGE_ALLOWED: Record<string, string[]> = {\n    git:  [\"status\",\"log\",\"diff\",\"add\",\"commit\",\"push\",\"pull\",\"fetch\",\"branch\",\"checkout\",\"stash\",\"show\",\"reset\",\"merge\",\"rebase\"],\n    pnpm: [\"install\",\"build\",\"test\",\"run\",\"lint\",\"exec\",\"--filter\"],\n    uv:   [\"sync\",\"run\",\"lock\",\"pip\",\"venv\",\"init\",\"add\",\"remove\",\"tree\"],\n    node: [],   // validated per-script\n    tsx:  [],   // validated per-script\n    rg:   [],   // ripgrep — all args allowed (read-only search)\n  };\n  const FORGE_SERVICES  = [\"squidley-api\",\"squidley-web\",\"squidley-desktop\",\"comfyui\"];\n  const SAFE_ROOT       = \"/mnt/ai\";\n  // .env file detection: matches .env, .env.local, .env.production, secrets.env, etc.\n  const ENV_FILE_RE     = /(^|\\/)(\\.env(\\.[^/]*)?|[^/]*\\.env)$/;\n  // Blocked write ops for shell strings\n  const SHELL_WRITE_RE  = /[>&]|\\b(rm|mv|cp|chmod|chown|touch|tee|dd|truncate|mktemp|install)\\b/;\n\n  function forgeValidate(cmd: string, args: string[]): { ok: boolean; reason?: string } {\n    // ── Grimoire pseudo-commands (file write/edit) ────────────────────────────\n    if (cmd === \"grimoire:write\" || cmd === \"grimoire:edit\") {\n      const filePath = args[0];\n      if (!filePath) return { ok: false, reason: `${cmd} requires a file path` };\n      if (ENV_FILE_RE.test(filePath)) return { ok: false, reason: \".env files cannot be modified\" };\n      return { ok: true };\n    }\n\n    // ── System services ───────────────────────────────────────────────────────\n    if (cmd === \"systemctl\") {\n      const [action, service] = args;\n      if (![\"restart\",\"status\",\"start\",\"stop\"].includes(action ?? \"\")) return { ok: false, reason: `systemctl action '${action}' not allowed` };\n      if (!FORGE_SERVICES.some(s => (service ??