 || cmd === \"tail\") {\n      for (const arg of args) {\n        if (!arg.startsWith(\"-\") && ENV_FILE_RE.test(arg)) {\n          return { ok: false, reason: `${cmd}: .env files are never exposed` };\n        }\n      }\n      return { ok: true };\n    }\n\n    // ── Pattern search: grep ──────────────────────────────────────────────────\n    if (cmd === \"grep\") {\n      // Block --include patterns that target .env\n      const badArg = args.find(a => ENV_FILE_RE.test(a) && !a.startsWith(\"-\"));\n      if (badArg) return { ok: false, reason: `grep: '${badArg}' — .env files are never exposed` };\n      return { ok: true };\n    }\n\n    // ── Pipe chains via shell (read-only only) ────────────────────────────────\n    if (cmd === \"sh\" || cmd === \"bash\") {\n      if (args[0] !== \"-c\" || typeof args[1] !== \"string\") {\n        return { ok: false, reason: `${cmd}: only '${cmd} -c \"...\"' form allowed` };\n      }\n      const shellStr = args[1];\n      if (SHELL_WRITE_RE.test(shellStr)) {\n        return { ok: false, reason: `${cmd}: write operations not allowed in shell command` };\n      }\n      if (ENV_FILE_RE.test(shellStr)) {\n        return { ok: false, reason: `${cmd}: .env file access not allowed` };\n      }\n      return { ok: true };\n    }\n\n    // ── mkdir — safe path only ──────────────────────────────────────────────\n    if (cmd === \"mkdir\") {\n      const target = args.filter(a => !a.startsWith(\"-\"))[0];\n      if (!target) return { ok: false, reason: \"mkdir requires a path argument\" };\n      if (!target.startsWith(SAFE_ROOT) && !target.startsWith(\".\")) {\n        return { ok: false, reason: `mkdir: path '${target}' outside safe scope (${SAFE_ROOT})` };\n      }\n      return { ok: true };\n    }\n\n    // ── sed — in-place file edits only, safe paths ──────────────────────────\n    if (cmd === \"sed\") {\n      // Must use -i for in-place editing on a specific file\n      if (!args.includes(\"-i\") && !args.some(a => a.startsWith(\"-i\"))) {\n        return { ok: false, reason: \"sed: only in-place editing (-i) allowed\" };\n      }\n      const fileArgs = args.filter(a => !a.startsWith(\"-\") && !a.startsWith(\"s/\") && !a.startsWith(\"s|\"));\n      for (const f of fileArgs) {\n        if (ENV_FILE_RE.test(f)) return { ok: false, reason: `sed: .env files are never modified` };\n      }\n      return { ok: true };\n    }\n\n    // ── ripgrep — full read-only search ─────────────────────────────────────\n    if (cmd === \"rg\") {\n      return { ok: true };\n    }\n\n    // ── Text tools ────────────────────────────────────────────────────────────\n    if ([\"wc\",\"sort\",\"uniq\",\"cut\",\"tr\",\"diff\",\"stat\",\"file\",\"du\",\"df\",\"ps\",\"env\",\"printenv\",\"echo\",\"date\",\"pwd\",\"which\",\"type\"].includes(cmd)) {\n      return { ok: true };\n    }\n\n    // ── pnpm / git / node / tsx ───────────────────────────────────────────────\n    if (!(cmd in FORGE_ALLOWED)) return { ok: false, reason: `'${cmd}' not in command whitelist` };\n    return { ok: true };\n  }\n\n  // In-memory session store — last 20 sessions\n  interface ForgeSessionRecord {\n    id: string; startedAt: number; doneAt?: number;\n    intent?: string;\n    status?: \"done\" | \"aborted\";\n    commands: Array<{ cmd: string; args: string[]; exitCode: number | null; output: string }>;\n    fileChanges: string[];\n  }\n  const forgeSessions: ForgeSessionRecord[] = [];\n  const MAX_FORGE_SESSIONS = 20;\n  let forgeAbort: AbortController | null = null;\n\n  // POST /forge/plan — AI generates a command plan from natural language intent\n  app.post<{ Body: { intent: string } }>(\"/forge/plan\", async (req, reply) => {\n    const pm = getService<{ complete: (opts: unknown) => Promise<{ text: string }> }>(\"provider-manager\");\n    if (!pm) return reply.status(503).send({ error: \"Provider not available\" });\n\n    const { intent } = req.body;\n    if (!intent) return reply.status(400).send({ error: \"intent required\" });\n\n    const systemPrompt = `You are Forge, Squidley's build execution planner for machine Mushin (Debian 12, /mnt/ai/squidley-v2 repo).\nGenerate a precise execution plan for the given build intent.\nAllowed commands: git (status/log/diff/add/commit/push/pull/fetch/branch/checkout/stash/show/reset/merge), pnpm (install/build/test/run/lint/--filter), uv (sync/run/lock/pip/venv/init/add/remove/tree — Python substrate), systemctl (restart/status — squidley-api/squidley-web/squidley-desktop only), curl (any URL), find/ls/cat/head/tail/grep/rg (code search under /mnt/ai — never .env files), mkdir (under /mnt/ai only), sed -i (in-place file edits — never .env), sh -c \"...\" (read-only pipe chains only), wc/sort/uniq/cut/stat/du/df/ps.\nFile operations: grimoire:write (create/overwrite files), grimoire:edit (search and replace in files). Both require path under /mnt/ai, never .env files.\nNO rm, mv, cp, chmod. For Python tasks, always use \"uv run\" — never raw python or pip.\n\nRespond with ONLY a JSON object (no markdown, no explanation):\n{\n  \"summary\": \"one sentence description of what will happen\",\n  \"risk\": \"low|medium|high\",\n  \"commands\": [\n    { \"cmd\": \"pnpm\", \"args\": [\"--filter\", \"@squidley/web\", \"build\"], \"description\": \"Build web app\" }\n  ],\n  \"estimatedDuration\": \"~30s\"\n}`;\n\n    try {\n      const result = await pm.complete({\n        tier: \"plan\",\n        messages: [\n          { role: \"system\", content: systemPrompt },\n          { role: \"user\", content: intent },\n        ],\n        reason: \"forge:plan\",\n        stream: false,\n      }) as { text: string };\n\n      // Strip markdown fences if present\n      const raw = result.text.replace(/^```(?:json)?\\n?/m, \"\").replace(/\\n?```$/m, \"\").trim();\n      const plan = JSON.parse(raw) as { summary: string; risk: string; commands: Array<{ cmd: string; args: string[]; description: string }>; estimatedDuration?: string };\n\n      // Validate every command against whitelist\n      const violations: string[] = [];\n      for (const c of plan.commands) {\n        const v = forgeValidate(c.cmd, c.args);\n        if (!v.ok) violations.push(`${c.cmd}: ${v.reason}`);\n      }\n      if (violations.length > 0) {\n        return reply.send({ ok: false, error: \"Plan contains disallowed commands\", violations, plan });\n      }\n      return reply.send({ ok: true, plan });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // POST /grimoire/respond — direct terminal-style answer, no planning layer\n  app.post<{\n    Body: {\n      intent: string;\n      cwd?: string;\n      conversationHistory?: Array<{ role: \"user\" | \"assistant\"; content: string }>;\n      model?: string;\n      provider?: string;\n    }\n  }>(\"/grimoire/respond\", async (req, reply) => {\n    const pm = getService<{ complete: (opts: unknown) => Promise<{ text: string; model?: string; tokensIn?: number; tokensOut?: number; estimatedCostUsd?: number; durationMs?: number }> }>(\"provider-manager\");\n    if (!pm) return reply.status(503).send({ ok: false, error: \"Provider not available\" });\n\n    const { intent, cwd, conversationHistory = [], model, provider } = req.body;\n    if (!intent?.trim()) return reply.status(400).send({ ok: false, error: \"intent required\" });\n\n    const workDir = cwd || process.env[\"SQUIDLEY_BASE_DIR\"] || \"/mnt/ai/squidley-v2\";\n    const responseModel = model ?? MODEL_ROLES.chat.model;\n    const responseProvider = provider ?? MODEL_ROLES.chat.provider;\n    const repoResolved = pathResolve(workDir);\n    const filesRead: string[] = [];\n    const FILE_PATH_RE = /(?:^|[\\s\"'`])(\\/?(?:[\\w.-]+\\/)*[\\w.-]+\\.(?:ts|tsx|js|mjs|json|yaml|yml|sh|toml|md))/g;\n    const candidatePaths: string[] = [];\n\n    let match: RegExpExecArray | null;\n    while ((match = FILE_PATH_RE.exec(intent)) !== null) candidatePaths.push(match[1]!.trim());\n\n    for (const candidate of [...new Set(candidatePaths)].slice(0, 4)) {\n      const absolute = candidate.startsWith(\"/\") ? candidate : pathJoin(workDir, candidate);\n      const resolved = pathResolve(absolute);\n      if (!resolved.startsWith(\"/mnt/ai\")) {\n        return reply.send({\n          ok: true,\n          text: `I couldn't inspect ${candidate} because it's outside the /mnt/ai workspace.`,\n          filesRead: [],\n          model: responseModel,\n          structuredError: true,\n        });\n      }\n      if (!resolved.startsWith(repoResolved)) {\n        return reply.send({\n          ok: true,\n          text: `I couldn't inspect ${candidate} because it's outside the current repo root ${workDir}.`,\n          filesRead: [],\n          model: responseModel,\n          structuredError: true,\n        });\n      }\n      try {\n        await access(resolved);\n      } catch {\n        return reply.send({\n          ok: true,\n          text: `I couldn't inspect ${candidate} because that file does not exist in this repo.`,\n          filesRead: [],\n          model: responseModel,\n          structuredError: true,\n        });\n      }\n      filesRead.push(candidate);\n    }\n\n    const fileBlocks: string[] = [];\n    for (const candidate of filesRead) {\n      const resolved = pathResolve(candidate.startsWith(\"/\") ? candidate : pathJoin(workDir, candidate));\n      const content = await readFile(resolved, \"utf-8\").catch(() => \"\");\n      if (content) {\n        fileBlocks.push(`File: ${candidate}\\n${content.slice(0, 6000)}`);\n      }\n    }\n\n    const systemPrompt = [\n      \"You are Grimoire, Squidley's terminal on Mushin.\",\n      \"Answer directly. Do not emit plans, JSON, or command lists unless the user explicitly asks for them.\",\n      \"Be precise and concise. If a file is missing or inaccessible, say that plainly.\",\n      \"Assume the user can run their own commands and curls; your job is to answer, explain, or suggest next commands when