wd  || process.env[\"SQUIDLEY_BASE_DIR\"] || \"/mnt/ai/squidley-v2\";\n    const planModel    = model    ?? MODEL_ROLES.grimoire.model;\n    const planProvider = provider ?? MODEL_ROLES.grimoire.provider;\n\n    req.log.info({ event: \"grimoire:intent\", intent, model: planModel });\n\n    // ── File reading pre-pass ────────────────────────────────────────────────\n    const filesRead: Record<string, string> = {};\n\n    const FILE_MOD_RE  = /\\b(edit|modify|change|update|fix|add to|remove from|refactor|delete|rename|rewrite|replace|patch|implement)\\b/i;\n    const FILE_PATH_RE = /(?:^|[\\s\"'`])(\\/?(?:[\\w.-]+\\/)*[\\w.-]+\\.(?:ts|tsx|js|mjs|json|env|yaml|yml|sh|toml|md))/g;\n\n    const SQUIDLEY_FILE_MAP: Record<string, string> = {\n      \"server.ts\":        \"apps/api/src/server.ts\",\n      \"server\":           \"apps/api/src/server.ts\",\n      \"chat route\":       \"apps/api/src/routes/chat.ts\",\n      \"chat.ts\":          \"apps/api/src/routes/chat.ts\",\n      \"model-roles\":      \"apps/api/src/config/model-roles.ts\",\n      \"model roles\":      \"apps/api/src/config/model-roles.ts\",\n      \"model-registry\":   \"apps/api/src/config/model-registry.ts\",\n      \"model registry\":   \"apps/api/src/config/model-registry.ts\",\n      \"nous registry\":    \"apps/api/src/config/model-registry.ts\",\n      \"squidley-voice\":   \"apps/api/src/config/squidley-voice.ts\",\n      \"voice prompt\":     \"apps/api/src/config/squidley-voice.ts\",\n    };\n\n    const intentLower = intent.toLowerCase();\n    const candidatePaths: string[] = [];\n\n    let m: RegExpExecArray | null;\n    while ((m = FILE_PATH_RE.exec(intent)) !== null) candidatePaths.push(m[1]!.trim());\n    for (const [term, path] of Object.entries(SQUIDLEY_FILE_MAP)) {\n      if (intentLower.includes(term)) candidatePaths.push(path);\n    }\n\n    if ((candidatePaths.length > 0 || FILE_MOD_RE.test(intent)) && candidatePaths.length > 0) {\n      const { readFile: rf } = await import(\"node:fs/promises\");\n      const { resolve: res, join: pj } = await import(\"node:path\");\n      const repoResolved = res(workDir);\n\n      for (const fp of [...new Set(candidatePaths)].slice(0, 4)) {\n        try {\n          const absPath = fp.startsWith(\"/\") ? fp : pj(workDir, fp);\n          const resolved = res(absPath);\n          if (!resolved.startsWith(repoResolved) && !resolved.startsWith(\"/mnt/ai\")) continue;\n\n          const content = await rf(resolved, \"utf-8\");\n          const preview = content.split(\"\\n\").slice(0, 250).join(\"\\n\");\n          filesRead[fp] = preview;\n\n          req.log.info({ event: \"grimoire:file-read\", file: fp });\n        } catch { /* not found — skip */ }\n      }\n    }\n\n    // ── Build system prompt ─────────────────────────────────────────────────\n    const fileBlock = Object.keys(filesRead).length > 0\n      ? \"\\n\\n# FILE CONTENTS (read before planning):\\n\" +\n        Object.entries(filesRead)\n          .map(([fp, c]) => `\\`\\`\\`\\n// ${fp}\\n${c}\\n\\`\\`\\``)\n          .join(\"\\n\\n\")\n      : \"\";\n\n    const historyBlock = conversationHistory.length > 0\n      ? \"\\n\\n# SESSION HISTORY:\\n\" +\n        conversationHistory.map(x => `${x.role.toUpperCase()}: ${x.content}`).join(\"\\n\")\n      : \"\";\n\n    const systemPrompt = `You are Grimoire — Squidley's conversational execution and operations agent.\nYou plan commands with clear reasoning, use session history, and read files before proposing changes.\nMachine: Mushin (Debian 12, /mnt/ai/squidley-v2)\nWorking directory: ${workDir}${historyBlock}${fileBlock}\n\nAllowed commands:\n- git: status, log, diff, add, commit, push, pull, fetch, branch, checkout, stash, show, reset, merge, rebase\n- pnpm: install, build, test, run, lint, exec, --filter\n- uv: sync, run, lock, pip, venv, init, add, remove, tree — Python substrate. Always use \"uv run\" for Python tools (ruff, mypy, ty, pytest). Never raw python or pip.\n  Python tool recipes: \"uv run ruff check .\" (lint), \"uv run ruff format --check .\" (format check), \"uv run ruff format .\" (format fix — REQUIRES APPROVAL), \"uv run mypy .\" or \"uv run ty check\" (typecheck), \"uv run pytest -q\" (test), \"uv pip list --format json\" (deps audit), \"uv tree\" (dep tree).\n  For format/lint/type intents: suggest python.format_check first, then offer python.format_fix with approval.\n  For dependency/package/audit intents: suggest python.deps_audit.\n  For \"run script\"/\"execute script\" intents: suggest python.script_run (REQUIRES APPROVAL, allowlisted scripts only).\n  For \"scaffold\"/\"new tool\"/\"create tool\" intents: suggest python.scaffold_tool.\n- systemctl: restart/status/start/stop — squidley-api/squidley-web/squidley-desktop only\n- curl: any URL — use -s for silent, -X for method, -H for headers, -d for body\n- find: any path under /mnt/ai — read-only flags only (-type, -name, -maxdepth, -mtime, -size, -newer, -not, -o, -print). NO -exec, -delete.\n- ls: any path\n- cat: any file EXCEPT .env, .env.*, *.env — never read secret files\n- head, tail: any file EXCEPT .env files\n- grep: -r, -n, -l, -i, -E flags — any path under /mnt/ai\n- rg (ripgrep): full flags — fast code search across large repos\n- mkdir: create directories under /mnt/ai only (use -p for parents)\n- sed -i: in-place file edits (never on .env files). Use sed -i 's/old/new/g' file.ts\n- sh -c \"...\": pipe chains for read-only commands (find | grep, cat | grep, etc.). NO >, >>, rm, mv, cp in shell string.\n- wc, sort, uniq, cut, tr, diff, stat, du, df, ps, echo, date, pwd, which\n\nFILE OPERATIONS — always use these structured commands, never shell redirects:\n- To CREATE or OVERWRITE a file: use { \"cmd\": \"grimoire:write\", \"args\": [\"PATH\", \"CONTENT\"], \"description\": \"Create file\" }\n  The full file content goes in args[1]. Path must be under /mnt/ai. Directories created automatically.\n  NEVER use 'cat > file << EOF', 'echo > file', or shell redirects. They bypass receipts and approval.\n- To EDIT a file (search and replace): use { \"cmd\": \"grimoire:edit\", \"args\": [\"PATH\", \"SEARCH\", \"REPLACE\"], \"description\": \"Edit file\" }\n  Finds the exact SEARCH string in the file and replaces it with REPLACE. For replace-all, add \"all\" as args[3].\n- For reading files: use cat, head, tail, or grep — these are read-only and auto-approved\n- For searching code: use rg (ripgrep) — fast, full regex support, all flags allowed\n- For finding files: use find with -maxdepth to avoid runaway recursion\n\nRULES:\n- ALWAYS use grimoire:write for file creation — never shell redirects (>, >>, cat <<EOF, tee)\n- Always prefer grimoire:edit (search/replace) over grimoire:write (full overwrite) for existing files\n- cat/head/tail/grep NEVER touch .env, .env.local, .env.*, *.env — block any intent to read secrets\n- Pipes: use sh -c \"find ... | grep ...\" form\n- Destructive ops (rm, mv, cp, chmod): NOT allowed\n- Read-only commands (grep, rg, find, cat, ls) score low risk automatically\n- For multi-file changes: read files first with cat/rg, then use grimoire:write or grimoire:edit for each\n\nNo arbitrary commands outside this list.\n\nReturn ONLY valid JSON — no markdown, no code fences:\n{\n  \"reasoning\": \"Explain WHY each step. Reference file contents if relevant. Note watch-outs.\",\n  \"summary\": \"One-sentence description of what this plan does\",\n  \"risk\": \"low|medium|high\",\n  \"commands\": [\n    { \"cmd\": \"git\", \"args\": [\"status\"], \"description\": \"Check working tree\" }\n  ],\n  \"estimatedDuration\": \"~5s\"\n}`;\n\n    try {\n      const tier = Object.keys(filesRead).length > 0 ? \"deep-review\" : \"plan\";\n      const result = await pm.complete({\n        tier,\n        model:             planModel,\n        preferredProvider: planProvider,\n        messages: [\n          { role: \"system\", content: systemPrompt },\n          { role: \"user\",   content: intent },\n        ],\n        reason: \"grimoire:plan-v2\",\n        stream: false,\n        meta:   { modelRole: \"grimoire\", roleFallbackChain: getRoleFallbackChain(\"grimoire\") },\n      }) as { text: string };\n\n      const raw     = result.text.replace(/^```(?:json)?\\n?/im, \"\").replace(/\\n?```\\s*$/im, \"\").trim();\n      const planData = JSON.parse(raw) as {\n        reasoning?: string;\n        summary: string; risk: string;\n        commands: Array<{ cmd: string; args: string[]; description: string }>;\n        estimatedDuration?: string;\n      };\n\n      const violations: string[] = [];\n      for (const c of planData.commands) {\n        const v = forgeValidate(c.cmd, c.args);\n        if (!v.ok) violations.push(`${c.cmd}: ${v.reason}`);\n      }\n      if (violations.length > 0) {\n        req.log.warn({ event: \"grimoire:plan-violations\", violations });\n        return reply.send({ ok: false, error: \"Plan contains disallowed commands\", violations, plan: planData });\n      }\n\n      // ── Inline Archelon scoring ─────────────────────────────────────────────\n      const { scoreForge } = await import(\"../../../../modules/system/archelon/index.js\");\n      const archelonResult = scoreForge({ intent, commands: planData.commands });\n\n      // Risk assessment — labels operation before execution\n      const risk = assessRisk(planData.commands);\n      const fileOpCount = planData.commands.filter(c => c.cmd === \"grimoire:write\" || c.cmd === \"grimoire:edit\" || c.cmd === \"sed\").length;\n      const hasFileWrites = fileOpCount > 0;\n      const multiFileBlock = fileOpCount > 3;\n      // File writes NEVER auto-approve — always require explicit approval\n      const autoApprove = hasFileWrites || multiFileBlock || risk.level === \"critical\" ? false : archelonResult.score <= 15;\n\n      req.log.info({ event: \"grimoire:plan-ok\", commandCount: planData.commands.length, risk: risk.level, riskReasons: risk.reasons, archelonScore: archelonResult.score, autoApprove, fileOps: fileOpCount, promptVersion: PROMPT_VERSIONS.grimoire });\n\n      // Notify for high/critical risk plans via the unified messaging\n      // service — default channel is Telegram, but any new channel\n      // registered later (Discord, Slack, etc.) picks up this path.\n      if (!autoApprove && (risk.level === \"high\" || risk.level === \"critical\")) {\n        void getMessagingService().notify({\n          type: \"grimoire-approval\",\n          priority: \"critical\",\n          data: { description: `[${risk.level.toUpperCase()}] ${planData.summary}` },\n        });\n      }\n\n      return reply.send({\n        ok:              true,\n        plan:            { summary: planData.summary, risk: risk.level, commands: planData.commands, estimatedDuration: planData.estimatedDuration },\n        reasoning:       planData.reasoning ?? \"\",\n        filesRead:       Object.keys(filesRead),\n        planModel,\n        archelonScore:   archelonResult.score,\n        archelonLevel:   archelonResult.level,\n        archelonFactors: archelonResult.factors,\n        autoApprove,\n        riskAssessment:  risk,\n        promptVersion:   PROMPT_VERSIONS.grimoire,\n      });\n    } catch (err) {\n      req.log.error({ event: \"grimoire:plan-failed\", error: String(err) });\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // POST /grimoire/correct — self-correction after execution failure\n  app.post<{\n    Body: {\n      originalIntent: string;\n      originalPlan:   { summary: string; commands: Array<{ cmd: string; args: string[]; description: string }> };\n      failedCmdIndex: number;\n      stdout:  string;\n      stderr:  string;\n      exitCode: number | null;\n      conversationHistory?: Array<{ role: \"user\" | \"assistant\"; content: string }>;\n      model?:    string;\n      provider?: string;\n    }\n  }>(\"/grimoire/correct\", async (req, reply) => {\n    const pm = getService<{ complete: (opts: unknown) => Promise<{ text: string }> }>(\"provider-manager\");\n    if (!pm) return reply.status(503).send({ error: \"Provider not available\" });\n\n    const { originalIntent, originalPlan, failedCmdIndex, stdout, stderr, exitCode, conversationHistory = [], model, provider } = req.body;\n\n    const planModel    = model    ?? MODEL_ROLES.grimoire.model;\n    const planProvider = provider ?? MODEL_ROLES.grimoire.provider;\n    const workDir      = process.env[\"SQUIDLEY_BASE_DIR\"] || \"/mnt/ai/squidley-v2\";\n    const failedCmd    = originalPlan.commands[failedCmdIndex];\n\n    const systemPrompt = `You are Grimoire's self-correction engine. A command execution failed.\nAnalyze what went wrong and propose a corrected plan. Be precise about the root cause.\nWorking directory: ${workDir}\n\nReturn ONLY valid JSON — no markdown, no code fences:\n{\n  \"analysis\": \"Root cause and what needs to change\",\n  \"canFix\": true|false,\n  \"correctedPlan\": {\n    \"reasoning\": \"Why this corrected approach will succeed\",\n    \"summary\": \"One-sentence description\",\n    \"risk\": \"low|medium|high\",\n    \"commands\": [...],\n    \"estimatedDuration\": \"~5s\"\n  }\n}\nIf canFix is false, set correctedPlan to null.`;\n\n    const failureMsg = [\n      `Original intent: ${originalIntent}`,\n      `Failed command (index ${failedCmdIndex}): ${failedCmd?.cmd} ${failedCmd?.args.join(\" \")}`,\n      `Exit code: ${exitCode ?? \"unknown\"}`,\n      stdout.trim() ? `Stdout (tail):\\n${stdout.slice(-600)}` : \"\",\n      stderr.trim() ? `Stderr (tail):\\n${stderr.slice(-600)}` : \"\",\n      `Propose a corrected plan.`,\n    ].filter(Boolean).join(\"\\n\\n\");\n\n    try {\n      req.log.info({ event: \"grimoire:self-correct-start\", failedCmd: failedCmd?.cmd, exitCode });\n\n      const result = await pm.complete({\n        tier:              \"plan\",\n        model:             planModel,\n        preferredProvider: planProvider,\n        messages: [\n          { role: \"system\",    content: systemPrompt },\n          ...conversationHistory,\n          { role: \"user\",      content: failureMsg },\n        ],\n        reason: \"grimoire:self-correct\",\n        stream: false,\n        meta:   { modelRole: \"grimoire\", roleFallbackChain: getRoleFallbackChain(\"grimoire\") },\n      }) as { text: string };\n\n      const raw  = result.text.replace(/^```(?:json)?\\n?/im, \"\").replace(/\\n?```\\s*$/im, \"\").trim();\n      const data = JSON.parse(raw) as {\n        analysis: string; canFix: boolean;\n        correctedPlan: { reasoning?: string; summary: string; risk: string; commands: Array<{ cmd: string; args: string[]; description: string }>; estimatedDuration?: string } | null;\n      };\n\n      if (data.correctedPlan) {\n        const violations: string[] = [];\n        for (const c of data.correctedPlan.commands) {\n          const v = forgeValidate(c.cmd, c.args);\n          if (!v.ok) violations.push(`${c.cmd}: ${v.reason}`);\n        }\n        if (violations.length > 0) {\n          return reply.send({ ok: true, canFix: false, analysis: `${data.analysis} (corrected plan had violations: ${violations.join(\", \")})`, correctedPlan: null });\n        }\n\n        const { scoreForge } = await import(\"../../../../modules/system/archelon/index.js\");\n        const archelonResult  = scoreForge({ intent: originalIntent, commands: data.correctedPlan.commands });\n        const correctionHasFileWrites = data.correctedPlan.commands.some((c: { cmd: string }) => c.cmd === \"grimoire:write\" || c.cmd === \"grimoire:edit\" || c.cmd === \"sed\");\n        const autoApprove     = correctionHasFileWrites ? false : archelonResult.score <= 15;\n\n        req.log.info({ event: \"grimoire:self-correct-done\", canFix: data.canFix, archelonScore: archelonResult.score, autoApprove });\n        return reply.send({ ok: true, analysis: data.analysis, canFix: data.canFix, correctedPlan: data.correctedPlan, autoApprove, archelonScore: archelonResult.score });\n      }\n\n     