t { randomUUID: wrid } = await import(\"node:crypto\");\n          const { appendFile: wraf } = await import(\"node:fs/promises\");\n          const { join: wrjn } = await import(\"node:path\");\n          const wrDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n          const wrDate = new Date().toISOString().slice(0, 10);\n          await wraf(wrjn(wrDir, `${wrDate}.jsonl`), JSON.stringify({\n            id: wrid(), timestamp: new Date().toISOString(),\n            componentType: \"tool-exec\", componentName: \"grimoire:write\",\n            moduleId: \"grimoire\", reason: \"grimoire:file-write\",\n            status: \"success\", surfacedToUser: true,\n            meta: { path: resolved, bytes: (content ?? \"\").length, rollbackId: rollbackEntry.id, verified: verification.verified },\n          }) + \"\\n\", \"utf-8\").catch(() => {});\n        } catch (err) {\n          cmdRecord.exitCode = 1;\n          cmdRecord.output = `Error: ${String(err)}\\n`;\n          send({ type: \"line\", stream: \"stderr\", text: cmdRecord.output, index: i });\n          send({ type: \"cmd-done\", index: i, cmd, exitCode: 1 });\n        }\n        if (aborted) break;\n        continue;\n      }\n\n      // ── grimoire:edit pseudo-command — search and replace ───────────────\n      if (cmd === \"grimoire:edit\") {\n        const [filePath, search, replace, allFlag] = args;\n        try {\n          const { resolve: pr } = await import(\"node:path\");\n          const { readFile: rf, writeFile: wf } = await import(\"node:fs/promises\");\n          const resolved = pr(filePath ?? \"\");\n          if (!resolved.startsWith(SAFE_ROOT)) throw new Error(`Path outside safe scope: ${resolved}`);\n          if (ENV_FILE_RE.test(resolved)) throw new Error(\".env files cannot be edited\");\n          const original = await rf(resolved, \"utf-8\");\n          if (!original.includes(search ?? \"\")) throw new Error(\"Search string not found in file\");\n          const isReplaceAll = allFlag === \"all\";\n          const updated = isReplaceAll\n            ? original.split(search ?? \"\").join(replace ?? \"\")\n            : original.replace(search ?? \"\", replace ?? \"\");\n          const count = isReplaceAll ? (original.split(search ?? \"\").length - 1) : 1;\n\n          // Rollback snapshot — capture original content before edit\n          const rollbackEntry = await snapshotBeforeEdit(resolved, original, updated, search ?? \"\", replace ?? \"\", isReplaceAll);\n          send({ type: \"line\", stream: \"stdout\", text: `Rollback snapshot: ${rollbackEntry.id}\\n`, index: i });\n\n          await wf(resolved, updated, \"utf-8\");\n\n          // Post-action verification\n          const verification = await verifyEdit(resolved, search ?? \"\", replace ?? \"\", isReplaceAll);\n          const verifyLine = verification.verified ? \"Verified: all checks passed\" : `Verification: ${verification.summary}`;\n\n          cmdRecord.exitCode = 0;\n          cmdRecord.output = `Edited: ${resolved} (${count} replacement${count !== 1 ? \"s\" : \"\"})\\n${verifyLine}\\n`;\n          send({ type: \"line\", stream: \"stdout\", text: cmdRecord.output, index: i });\n          send({ type: \"cmd-done\", index: i, cmd, exitCode: 0, verification } as Record<string, unknown>);\n\n          // Receipt for exec-path edit\n          const { randomUUID: erid } = await import(\"node:crypto\");\n          const { appendFile: eraf } = await import(\"node:fs/promises\");\n          const { join: erjn } = await import(\"node:path\");\n          const erDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n          const erDate = new Date().toISOString().slice(0, 10);\n          await eraf(erjn(erDir, `${erDate}.jsonl`), JSON.stringify({\n            id: erid(), timestamp: new Date().toISOString(),\n            componentType: \"tool-exec\", componentName: \"grimoire:edit\",\n            moduleId: \"grimoire\", reason: \"grimoire:file-edit\",\n