wd: repoRoot, stdio: [\"ignore\",\"pipe\",\"pipe\"] });\n        let out = \"\";\n        gs.stdout.on(\"data\", (c: Buffer) => { out += c.toString(); });\n        gs.on(\"close\", () => {\n          const changes = out.split(\"\\n\").filter(Boolean).map(l => l.trim());\n          if (changes.length) {\n            session.fileChanges = [...new Set([...session.fileChanges, ...changes])];\n            send({ type: \"file-changes\", changes });\n          }\n          resolve();\n        });\n      });\n    }\n\n    session.doneAt = Date.now();\n    forgeSessions.unshift(session);\n    if (forgeSessions.length > MAX_FORGE_SESSIONS) forgeSessions.pop();\n\n    if (aborted) {\n      send({ type: \"aborted\", sessionId });\n      if (forgeAbort === ctrl) forgeAbort = null;\n      reply.raw.write(\"data: [DONE]\\n\\n\");\n      reply.raw.end();\n      return;\n    }\n\n    send({ type: \"session-done\", sessionId, durationMs: session.doneAt - session.startedAt });\n    if (forgeAbort === ctrl) forgeAbort = null;\n    reply.raw.write(\"data: [DONE]\\n\\n\");\n    reply.raw.end();\n  });\n\n  // POST /forge/abort — kill the running session\n  app.post(\"/forge/abort\", async (_req, reply) => {\n    if (forgeAbort) { forgeAbort.abort(); forgeAbort = null; }\n    return reply.send({ ok: true });\n  });\n\n  // GET /forge/sessions — list recent sessions\n  app.get(\"/forge/sessions\", async (_req, reply) => {\n    return reply.send({ ok: true, sessions: forgeSessions.map(s => ({\n      id: s.id, startedAt: s.startedAt, doneAt: s.doneAt, intent: s.intent, status: s.status ?? \"done\",\n      commandCount: s.commands.length, fileChanges: s.fileChanges,\n      exitCodes: s.commands.map(c => c.exitCode),\n    })) });\n  });\n\n  // ── Grimoire file write — create or overwrite files ──────────────────────\n  app.post<{ Body: { path: string; content: string; createDirs?: boolean; reason?: string } }>(\"/grimoire/write\", async (req, reply) => {\n    const { path: filePath, content, createDirs = false, reason } = req.body;\n    if (!filePath || content === undefined) return reply.status(400).send({ ok: false, error: \"path and content required\" });\n\n    // Resolve to absolute\n    const { resolve: pathResolve, dirname } = await import(\"node:path\");\n    const resolved = pathResolve(filePath);\n\n    // Safety: must be under SAFE_ROOT\n    if (!resolved.startsWith(SAFE_ROOT)) {\n      return reply.status(403).send({ ok: false, error: `Path '${resolved}' outside safe scope (${SAFE_ROOT})` });\n    }\n    // Never write .env files\n    if (ENV_FILE_RE.test(resolved)) {\n      return reply.status(403).send({ ok: false, error: \".env files cannot be written by Grimoire\" });\n    }\n    // No binary injection — content must be string\n    if (typeof content !== \"string\") {\n      return reply.status(400).send({ ok: false, error: \"content must be a string\" });\n    }\n\n    try {\n      const { writeFile: wf, mkdir: mk } = await import(\"node:fs/promises\");\n      if (createDirs) await mk(dirname(resolved), { recursive: true });\n      await wf(resolved, content, \"utf-8\");\n\n      // Receipt\n      const { randomUUID: rid } = await import(\"node:crypto\");\n      const { appendFile: af2 } = await import(\"node:fs/promises\");\n      const { join: pj2 } = await import(\"node:path\");\n      const receiptsDir = process.env[\"SQUIDLEY_RECEIPTS_DIR\"] ?? \"./state/receipts\";\n      await mk(receiptsDir, { recursive: true });\n      const date = new Date().toISOString().slice(0, 10);\n      const rEntry = {\n        id: rid(), timestamp: new Date().toISOString(),\n        componentType: \"tool-exec\", componentName: \"grimoire:write\",\n        moduleId: \"grimoire\", reason: reason ?? \"grimoire:file-write\",\n        status: \"success\", surfacedToUser: true,\n        meta: { path: resolved, bytes: content.length },\n      };\n      await af2(pj2(receiptsDir, `${date}.jsonl`), JSON.stringify(rEntry) + \"\\n\", \"utf-8\").catch(() => {});\n