t { readdir, readFile, mkdir } = await import(\"node:fs/promises\");\n    const { join } = await import(\"node:path\");\n    const dir = reportsDir();\n    await mkdir(dir, { recursive: true });\n    try {\n      const date = req.query.date ?? new Date().toISOString().slice(0, 10);\n      // If date=all, return last 7 days merged\n      let files: string[] = [];\n      if (date === \"all\") {\n        const all = await readdir(dir);\n        files = all.filter(f => f.endsWith(\".jsonl\") && !f.startsWith(\"archelon-\")).sort().reverse().slice(0, 7);\n      } else {\n        files = [`${date}.jsonl`];\n      }\n      const reports: unknown[] = [];\n      for (const file of files) {\n        try {\n          const raw = await readFile(join(dir, file), \"utf-8\");\n          for (const line of raw.split(\"\\n\").filter(Boolean)) {\n            try { reports.push(JSON.parse(line)); } catch { /* skip */ }\n          }\n        } catch { /* file may not exist */ }\n      }\n      reports.sort((a, b) => ((b as { timestamp: string }).timestamp > (a as { timestamp: string }).timestamp ? 1 : -1));\n      const limit = parseInt(req.query.limit ?? \"100\");\n      return reply.send({ ok: true, reports: reports.slice(0, limit) });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, reports: [], error: String(err) });\n    }\n  });\n\n  app.post<{ Body: { agentId: string; agentName: string; summary: string; output: string; meta?: Record<string, unknown> } }>(\"/agents/reports\", async (req, reply) => {\n    const { writeFile, mkdir, appendFile } = await import(\"node:fs/promises\");\n    const { join } = await import(\"node:path\");\n    const dir = reportsDir();\n    await mkdir(dir, { recursive: true });\n    const entry = {\n      id: `rpt-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,\n      agentId: req.body.agentId,\n      agentName: req.body.agentName,\n      summary: req.body.summary,\n      output: req.body.output,\n      meta: req.body.meta ?? {},\n      timestamp: new Date().toISOString(),\n    };\n    const date = entry.timestamp.slice(0, 10);\n    try {\n      await appendFile(join(dir, `${date}.jsonl`), JSON.stringify(entry) + \"\\n\");\n    } catch (err) {\n      req.log.error({ event: \"agents-report-write-failed\", error: String(err) });\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n    return reply.send({ ok: true, id: entry.id });\n  });\n\n  app.get(\"/agents/list\", async (req, reply) => {\n    const { readdir } = await import(\"node:fs/promises\");\n    const dir = reportsDir();\n    // Compute last run per agent from today + yesterday files\n    const lastRuns: Record<string, string> = {};\n    try {\n      await import(\"node:fs/promises\").then(async ({ mkdir }) => mkdir(dir, { recursive: true }));\n      const { readFile } = await import(\"node:fs/promises\");\n      const { join } = await import(\"node:path\");\n      const today = new Date().toISOString().slice(0, 10);\n      const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);\n      for (const dateStr of [today, yesterday]) {\n        try {\n          const raw = await readFile(join(dir, `${dateStr}.jsonl`), \"utf-8\");\n          for (const line of raw.split(\"\\n\").filter(Boolean)) {\n            try {\n              const e = JSON.parse(line) as { agentId: string; timestamp: string };\n              if (!lastRuns[e.agentId] || e.timestamp > lastRuns[e.agentId]!) lastRuns[e.agentId] = e.timestamp;\n            } catch { /* skip */ }\n          }\n        } catch { /* no file */ }\n      }\n    } catch (err) { req.log.warn({ event: \"agents-list-lastrun-failed\", error: String(err) }); }\n    const agents = SCHEDULER_ENTRIES.map(a => ({ ...a, lastRun: lastRuns[a.id] ?? null }));\n    return reply.send({ ok: true, agents });\n  });\n\n  app.get(\"/archivum/status\", async (_req, reply) => {\n    const arch = getService<{ vlModel: string }>(\"archivum\");\n    return reply.send({ ok: !!arch, vlModel: arch?.vlModel ?? null });\n  });\n\n  // ── Archivum identity cleanup — remove identity tags from session archives ──\n  app.get(\"/archivum/cleanup-identity\", async (req, reply) => {\n    const { readdir, readFile, writeFile } = await import(\"node:fs/promises\");\n    const { join } = await import(\"node:path\");\n    const archivumDir = process.env[\"ARCHIVUM_UPLOAD_DIR\"] ?? (process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd()) + \"/state/uploads\";\n    const IDENTITY_TAGS = [\"jeff-profile\", \"preferences\", \"personality\", \"squirrel\", \"career\", \"doctrine\", \"identity\"];\n\n    const files = await readdir(archivumDir).catch(() => [] as string[]);\n    let cleaned = 0;\n    const details: Array<{ file: string; removedTags: string[] }> = [];\n\n    for (const f of files.filter(f => f.endsWith(\".json\"))) {\n      try {\n        const filePath = join(archivumDir, f);\n        const raw = await readFile(filePath, \"utf-8\");\n        const entry = JSON.parse(raw);\n        const text: string = entry?.extraction?.text ?? \"\";\n        const summary: string = entry?.extraction?.summary ?? \"\";\n        const topics: string[] = entry?.extraction?.topics ?? [];\n        const title: string = entry?.title ?? entry?.filename ?? \"\";\n\n        const isSession =\n          text.trim().startsWith(\"# Session Archive\") ||\n          summary.includes(\"Session Archive\") ||\n          topics.some((t: string) => [\"session-archive\", \"transcript\", \"session\"].includes(t)) ||\n          title.includes(\"Session Archive\") ||\n          f.includes(\"session-archive\");\n\n        if (!isSession) continue;\n\n        const tagsToRemove = topics.filter((t: string) => IDENTITY_TAGS.includes(t));\n        if (tagsToRemove.length === 0) continue;\n\n        entry.extraction.topics = topics.filter((t: string) => !IDENTITY_TAGS.includes(t));\n        await writeFile(filePath, JSON.stringify(entry, null, 2), \"utf-8\");\n        cleaned++;\n        details.push({ file: f, removedTags: tagsToRemove });\n      } catch { /* skip malformed */ }\n    }\n\n    req.log.info({ event: \"archivum-identity-cleanup\", cleaned, details });\n    return reply.send({ ok: true, cleaned, details });\n  });\n\n  // ── Version ───────────────────────────────────────────────────────────────\n  app.get(\"/version\", async (_req, reply) => {\n    const { readFileSync } = await import(\"node:fs\");\n    const { join } = await import(\"node:path\");\n    let version = \"2.0.0\";\n    try {\n      const pkg = JSON.parse(readFileSync(join(process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd(), \"package.json\"), \"utf-8\"));\n      version = pkg.version ?? \"2.0.0\";\n    } catch { /* use default */ }\n    const health = await fetch(`http://localhost:${process.env[\"PORT\"] ?? 18791}/health`).then(r => r.json()).catch(() => ({})) as { modules?: Record<string, unknown> };\n    return reply.send({\n      platform: process.env[\"SQUIDLEY_PLATFORM_NAME\"] ?? \"Squidley\",\n      version,\n      buildDate: new Date().toISOString(),\n      modulesLoaded: Object.keys((health as { modules?: Record<string, unknown> }).modules ?? {}).length,\n    });\n  });\n\n  // ── Brain Map — routing intelligence API ──────────────────────────────────\n\n  app.get<{ Querystring: { limit?: string } }>(\"/brain-map/decisions\", async (req, reply) => {\n    const r = getService<{ getRecentDecisions: (n?: number) => RoutingDecision[] }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      const limit = Math.min(200, parseInt(req.query.limit ?? \"100\"));\n      return reply.send({ ok: true, decisions: r.getRecentDecisions(limit) });\n    } catch (err) { return reply.status(500).send({ ok: false, error: String(err) }); }\n  });\n\n  app.get<{ Querystring: { limit?: string } }>(\"/brain-map/signals\", async (req, reply) => {\n    const r = getService<{ getRecentSignals: (n?: number) => SignalEntry[] }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      const limit = Math.min(200, parseInt(req.query.limit ?? \"100\"));\n      return reply.send({ ok: true, signals: r.getRecentSignals(limit) });\n    } catch (err) { return reply.status(500).send({ ok: false, error: String(err) }); }\n  });\n\n  app.get(\"/brain-map/performance\", async (_req, reply) => {\n    const r = getService<{ getModelPerformance: () => ModelPerf[] }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      return reply.send({ ok: true, performance: r.getModelPerformance() });\n    } catch (err) { return reply.status(500).send({ ok: false, error: String(err) }); }\n  });\n\n  app.get(\"/brain-map/stats\", async (_req, reply) => {\n    const r = getService<{ getStats: () => { totalDecisions: number; totalSignals: number; dailyBudgetUsd: number } }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      return reply.send({ ok: true, ...r.getStats() });\n    } catch (err) { return reply.status(500).send({ ok: false, error: String(err) }); }\n  });\n\n  app.post<{ Body: { decisionId: string; signal: QualitySignal } }>(\"/brain-map/signal\", async (req, reply) => {\n    const r = getService<{ recordSignal: (id: string, s: QualitySignal) => void }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    const { decisionId, signal } = req.body;\n    if (!decisionId || !signal) return reply.status(400).send({ ok: false, error: \"decisionId and signal required\" });\n    try {\n      r.recordSignal(decisionId, signal);\n    } catch (err) {\n      req.log.warn({ event: \"brain-map-signal-failed\", decisionId, signal, error: String(err) });\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n    return reply.send({ ok: true });\n  });\n\n  // POST /brain-map/route — classify a message and return routing decision without executing\n  app.post<{ Body: { message: string; hasArchivumContext?: boolean; overrideProvider?: string } }>(\"/brain-map/route\", async (req, reply) => {\n    const r = getService<{ route: (req: RouteRequest) => Promise<RouteDecision> }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      const decision = await r.route(req.body);\n      return reply.send({ ok: true, decision });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Brain Map V2: Self-Optimization ────────────────────────────────────────\n\n  // GET /brain-map/optimization — get optimization recommendations\n  app.get<{ Querystring: { status?: string } }>(\"/brain-map/optimization\", async (req, reply) => {\n    const r = getService<{ getOptimizationRecommendations: (status?: string) => unknown }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      const recommendations = r.getOptimizationRecommendations(req.query.status || undefined);\n      return reply.send({ ok: true, recommendations });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // POST /brain-map/optimization/run — trigger optimization review on demand\n  app.post(\"/brain-map/optimization/run\", async (_req, reply) => {\n    const r = getService<{ runOptimizationReview: () => Promise<unknown> }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      const results = await r.runOptimizationReview();\n      return reply.send({ ok: true, results });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // POST /brain-map/optimization/:id/accept — accept a recommendation\n  app.post<{ Params: { id: string } }>(\"/brain-map/optimization/:id/accept\", async (req, reply) => {\n    const r = getService<{ acceptRecommendation: (id: string) => void }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      r.acceptRecommendation(req.params.id);\n      return reply.send({ ok: true });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // POST /brain-map/optimization/:id/reject — reject a recommendation\n  app.post<{ Params: { id: string } }>(\"/brain-map/optimization/:id/reject\", async (req, reply) => {\n    const r = getService<{ rejectRecommendation: (id: string) => void }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      r.rejectRecommendation(req.params.id);\n      return reply.send({ ok: true });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // GET /brain-map/failure-rates — get failure rates by task×provider\n  app.get<{ Querystring: { days?: string } }>(\"/brain-map/failure-rates\", async (req, reply) => {\n    const r = getService<{ getFailureRates: (days?: number) => unknown }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      const days = req.query.days ? parseInt(req.query.days, 10) : 7;\n      const rates = r.getFailureRates(days);\n      return reply.send({ ok: true, rates });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // GET /brain-map/cost-analysis — get cost breakdown by task type\n  app.get<{ Querystring: { days?: string } }>(\"/brain-map/cost-analysis\", async (req, reply) => {\n    const r = getService<{ getCostByTaskType: (days?: number) => unknown }>(\"model-router\");\n    if (!r) return reply.status(503).send({ ok: false, error: \"Brain Map not available\" });\n    try {\n      const days = req.query.days ? parseInt(req.query.days, 10) : 7;\n      const analysis = r.getCostByTaskType(days);\n      return reply.send({ ok: true, analysis });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Animus — Idea Vault ──────────────────────────────────────────────────\n\n  const animus = getService<{\n    create:  (content: string, audioPath?: string | null) => unknown;\n    get:     (id: string) => unknown;\n    list:    () => unknown[];\n    stale:   () => unknown[];\n    trash:   (id: string) => boolean;\n    park:    (id: string) => unknown;\n    unpark:  (id: string) => unknown;\n    promote:       (id: string, destination: string) => unknown;\n    updateContent: (id: string, content: string) => unknown;\n    count:         () => number;\n  }>(\"animus\");\n\n  app.post<{ Body: { content: string; audio_path?: string } }>(\"/animus/ideas\", async (req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    const { content, audio_path } = req.body ?? {};\n    if (!content?.trim()) return reply.status(400).send({ ok: false, error: \"content is required\" });\n    const idea = animus.create(content.trim(), audio_path ?? null);\n    return reply.status(201).send({ ok: true, idea });\n  });\n\n  app.get(\"/animus/ideas\", async (_req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    return reply.send({ ok: true, ideas: animus.list() });\n  });\n\n  app.get(\"/animus/ideas/stale\", async (_req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    return reply.send({ ok: true, ideas: animus.stale() });\n  });\n\n  app.delete<{ Params: { id: string } }>(\"/animus/ideas/:id\", async (req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    const ok = animus.trash(req.params.id);\n    if (!ok) return reply.status(404).send({ ok: false, error: \"Idea not found\" });\n    return reply.send({ ok: true });\n  });\n\n  app.patch<{ Params: { id: string } }>(\"/animus/ideas/:id/park\", async (req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    const idea = animus.park(req.params.id);\n    if (!idea) return reply.status(404).send({ ok: false, error: \"Idea not found\" });\n    return reply.send({ ok: true, idea });\n  });\n\n  app.patch<{ Params: { id: string } }>(\"/animus/ideas/:id/unpark\", async (req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    const idea = animus.unpark(req.params.id);\n    if (!idea) return reply.status(404).send({ ok: false, error: \"Idea not found\" });\n    return reply.send({ ok: true, idea });\n  });\n\n  app.patch<{ Params: { id: string }; Body: { content: string } }>(\"/animus/ideas/:id\", async (req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    const { content } = req.body ?? {};\n    if (!content?.trim()) return reply.status(400).send({ ok: false, error: \"content is required\" });\n    const idea = animus.updateContent(req.params.id, content.trim());\n    if (!idea) return reply.status(404).send({ ok: false, error: \"Idea not found\" });\n    return reply.send({ ok: true, idea });\n  });\n\n  app.patch<{ Params: { id: string }; Body: { destination: \"archivum\" | \"fabrica\"; title?: string } }>(\"/animus/ideas/:id/promote\", async (req, reply) => {\n    if (!animus) return reply.status(503).send({ ok: false, error: \"Animus not available\" });\n    const { destination, title } = req.body ?? {};\n    if (!destination) return reply.status(400).send({ ok: false, error: \"destination required\" });\n\n    const existing = animus.get(req.params.id) as { content?: string } | null;\n    if (!existing) return reply.status(404).send({ ok: false, error: \"Idea not found\" });\n\n    let promotedTo: string = destination;\n\n    if (destination === \"archivum\") {\n      try {\n        const { saveTextNote } = await import(\"../../../../modules/integrations/archivum/index.js\");\n        const entry = await saveTextNote({\n          title: title ?? (existing.content ?? \"\").slice(0, 80),\n          content: existing.content ?? \"\",\n          tags: [\"animus\", \"idea\"],\n        });\n        promotedTo = `archivum:${entry.id}`;\n      } catch (err) {\n        return reply.status(500).send({ ok: false, error: `Archivum save failed: ${String(err)}` });\n      }\n    }\n    // fabrica promotion is handled client-side via sessionStorage → /build\n\n    const idea = animus.promote(req.params.id, promotedTo);\n    return reply.send({ ok: true, idea, promotedTo });\n  });\n\n  // ── Alert Pipeline ──────────────────────────────────────────────────────────\n\n  app.get(\"/alerts/pending\", async (_req, reply) => {\n    const watcher = getService<{ getPendingAlerts: () => Promise<unknown[]> }>(\"alert-watcher\");\n    if (!watcher) return reply.status(503).send({ ok: false, error: \"Alert watcher not available\" });\n    try {\n      const alerts = await watcher.getPendingAlerts();\n      return reply.send({ ok: true, alerts });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  app.post<{ Params: { id: string } }>(\"/alerts/:id/acknowledge\", async (req, reply) => {\n    const watcher = getService<{ acknowledgeAlert: (id: string) => Promise<void> }>(\"alert-watcher\");\n    if (!watcher) return reply.status(503).send({ ok: false, error: \"Alert watcher not available\" });\n    try {\n      await watcher.acknowledgeAlert(req.params.id);\n      return reply.send({ ok: true });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Animus Voice STT ─────────────────────────────────────────────────────\n\n  app.post(\"/animus/stt\", async (req, reply) => {\n    try {\n      const { randomUUID } = await import(\"node:crypto\");\n      const { join, resolve: resolvePath } = await import(\"node:path\");\n      const { writeFile, mkdir } = await import(\"node:fs/promises\");\n\n      const multipartReq = req as typeof req & { file: () => Promise<{ file: AsyncIterable<Uint8Array>; filename?: string } | undefined> };\n      const data = await multipartReq.file();\n      if (!data) return reply.status(400).send({ ok: false, error: \"Audio file required\" });\n\n      // Save audio to animus audio dir\n      const audioDir = resolvePath(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"animus\", \"audio\");\n      await mkdir(audioDir, { recursive: true });\n      const filename = `${Date.now()}-${randomUUID().slice(0, 8)}.webm`;\n      const audioPath = join(audioDir, filename);\n\n      const chunks: Buffer[] = [];\n      for await (const chunk of data.file) chunks.push(chunk as Buffer);\n      await writeFile(audioPath, Buffer.concat(chunks));\n\n      // Transcribe using Voice module (faster-whisper, handles any format)\n      const voice = getService<{ transcribe: (path: string) => Promise<string> }>(\"voice\");\n      let text = \"\";\n      if (voice) {\n        try {\n          text = await voice.transcribe(audioPath);\n        } catch (err) {\n          req.log.warn({ event: \"animus-stt-failed\", error: String(err) });\n        }\n      }\n\n      return reply.send({\n        ok: true,\n        text: text || \"\",\n        audio_path: audioPath,\n        audio_url: `/animus/audio/${filename}`,\n      });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // Serve Animus audio files\n  app.get<{ Params: { filename: string } }>(\"/animus/audio/:filename\", async (req, reply) => {\n    const { resolve: resolvePath } = await import(\"node:path\");\n    const { createReadStream } = await import(\"node:fs\");\n    const { safeServeFile } = await import(\"../lib/safe-serve-file.js\");\n    const audioDir = resolvePath(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"animus\", \"audio\");\n    try {\n      const filePath = safeServeFile(audioDir, req.params.filename);\n      reply.header(\"Content-Type\", \"audio/webm\");\n      return reply.send(createReadStream(filePath));\n    } catch (err) {\n      return reply.status(403).send({ ok: false, error: (err as Error).message });\n    }\n  });\n\n  // ── Archelon — model scores from Crucible ────────────────────────────────\n\n  app.get<{ Querystring: { modelId?: string; limit?: string } }>(\"/archelon/model-scores\", async (req, reply) => {\n    const { modelId, limit = \"10\" } = req.query;\n    if (!modelId) return reply.status(400).send({ error: \"modelId query param required\" });\n\n    const crucibulumUrl = process.env[\"CRUCIBULUM_URL\"] ?? \"http://localhost:18795\";\n    try {\n      const res = await fetch(\n        `${crucibulumUrl}/api/scores?modelId=${encodeURIComponent(modelId)}&limit=${parseInt(limit, 10)}`,\n        { signal: AbortSignal.timeout(5_000) },\n      );\n      if (!res.ok) return reply.status(502).send({ error: `Crucible returned ${res.status}` });\n      const data = await res.json();\n      return reply.send(data);\n    } catch (err) {\n      return reply.status(503).send({ error: `Crucible unreachable: ${String(err).slice(0, 100)}` });\n    }\n  });\n\n  // ── Archelon — sentinel findings + forge risk scoring ─────────────────────\n\n  app.get<{ Querystring: { date?: string; limit?: string; severity?: string; category?: string } }>(\"/archelon/findings\", async (req, reply) => {\n    const { readdir, readFile } = await import(\"node:fs/promises\");\n    const { join, resolve }    = await import(\"node:path\");\n    try {\n      const reportsDir = resolve(process.env[\"SQUIDLEY_REPORTS_DIR\"] ?? \"./state/reports\");\n      const { date, limit = \"100\", severity, category } = req.query;\n      const files = await readdir(reportsDir).catch(() => [] as string[]);\n      const targetFile = date\n        ? `archelon-${date}.jsonl`\n        : files.filter(f => f.startsWith(\"archelon-\") && f.endsWith(\".jsonl\")).sort().reverse()[0];\n      if (!targetFile) return reply.send({ ok: true, findings: [], dates: [] });\n      const raw = await readFile(join(reportsDir, targetFile), \"utf-8\").catch(() => \"\");\n      let findings: ArchelonFinding[] = raw.split(\"\\n\").filter(Boolean).map(l => {\n        try { return JSON.parse(l) as ArchelonFinding; } catch { return null; }\n      }).filter(Boolean) as ArchelonFinding[];\n      if (severity) findings = findings.filter(f => f.severity === severity);\n      if (category) findings = findings.filter(f => f.category === category);\n      findings = findings.slice(-Math.min(500, parseInt(limit)));\n      const dates = files\n        .filter(f => f.startsWith(\"archelon-\") && f.endsWith(\".jsonl\"))\n        .map(f => f.replace(\"archelon-\", \"\").replace(\".jsonl\", \"\"))\n        .sort().reverse();\n      return reply.send({ ok: true, findings: findings.reverse(), dates });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // POST /archelon/findings — External finding ingestion (used by Grimoire Scan, etc.)\n  app.post<{ Body: { severity: string; category: string; title: string; detail: string; recommend?: string } }>(\"/archelon/findings\", async (req, reply) => {\n    const { appendFile, mkdir } = await import(\"node:fs/promises\");\n    const { join, resolve } = await import(\"node:path\");\n    const { randomUUID } = await import(\"node:crypto\");\n    try {\n      const { severity = \"info\", category = \"audit\", title, detail, recommend } = req.body ?? {};\n      if (!title || !detail) return reply.status(400).send({ ok: false, error: \"title and detail required\" });\n\n      const reportsDir = resolve(process.env[\"SQUIDLEY_REPORTS_DIR\"] ?? \"./state/reports\");\n      await mkdir(reportsDir, { recursive: true });\n\n      // Normalize fingerprint for dedup (same logic as Archelon.postFinding)\n      const normalizedTitle = title.toLowerCase().replace(/\\d+/g, \"N\").replace(/\\$[\\d.]+/g, \"$N\").replace(/\\s+/g, \" \").trim();\n      const fp = `${category}:${normalizedTitle}`;\n\n      const finding: ArchelonFinding = {\n        id: randomUUID(),\n        timestamp: new Date().toISOString(),\n        severity: ([\"info\", \"warn\", \"critical\"].includes(severity) ? severity : \"info\") as \"info\" | \"warn\" | \"critical\",\n        category: ([\"health\", \"anomaly\", \"budget\", \"safety\", \"forge\", \"audit\", \"model_regression\"].includes(category) ? category : \"audit\") as FindingCategory,\n        title,\n        detail,\n        ...(recommend ? { recommend } : {}),\n        fingerprint: fp,\n      };\n\n      // 24-hour dedup: check today's file for matching fingerprint\n      const todayFile = join(reportsDir, `archelon-${new Date().toISOString().slice(0, 10)}.jsonl`);\n      try {\n        const { readFile } = await import(\"node:fs/promises\");\n        const existing = await readFile(todayFile, \"utf-8\").catch(() => \"\");\n        const isDupe = existing.split(\"\\n\").filter(Boolean).some(line => {\n          try { return (JSON.parse(line) as { fingerprint?: string }).fingerprint === fp; }\n          catch { return false; }\n        });\n        if (isDupe) return reply.send({ ok: true, deduplicated: true, fingerprint: fp });\n      } catch { /* file doesn't exist yet */ }\n\n      await appendFile(todayFile, JSON.stringify(finding) + \"\\n\", \"utf-8\");\n      return reply.send({ ok: true, finding });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  app.post<{ Body: ForgeScoreInput }>(\"/archelon/score-plan\", async (req, reply) => {\n    try {\n      const { scoreForge } = await import(\"../../../../modules/system/archelon/index.js\");\n      const result: ForgeScoreResult = scoreForge(req.body);\n      return reply.send({ ok: true, ...result });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Symposium — brainstorm crystallization ────────────────────────────────\n\n  app.post<{\n    Body: {\n      messages: Array<{ role: string; content: string }>;\n      sessionId?: string;\n    }\n  }>(\"/symposium/crystallize\", async (req, reply) => {\n    const pm = getService<{\n      complete: (opts: CompleteOptions) => Promise<{ text: string; tokensIn: number; tokensOut: number; model: string; durationMs: number; estimatedCostUsd: number }>;\n    }>(\"provider-manager\");\n    if (!pm) return reply.status(503).send({ ok: false, error: \"Provider not available\" });\n\n    const { messages, sessionId } = req.body;\n    if (!messages?.length) return reply.status(400).send({ ok: false, error: \"messages required\" });\n\n    const t0 = Date.now();\n    const CRYSTALLIZE_PROMPT = `You are extracting a project brief from a brainstorming conversation.\n\nReturn valid JSON only — no markdown, no prose, no code fences. Schema:\n{\n  \"projectName\": \"short descriptive name\",\n  \"summary\": \"2-3 sentence description of the project and its goal\",\n  \"taskList\": [\"actionable task 1\", \"actionable task 2\", \"...\"],\n  \"source\": \"symposium\"\n}\n\nExtract from the conversation. Be concrete. Don't pad.`;\n\n    try {\n      const transcript = messages\n        .map(m => `${m.role === \"user\" ? \"Jeff\" : \"Squidley\"}: ${m.content}`)\n        .join(\"\\n\\n\");\n\n      const result = await pm.complete({\n        tier: \"chat\",\n        messages: [\n          { role: \"system\", content: CRYSTALLIZE_PROMPT },\n          { role: \"user\", content: transcript },\n        ],\n        model: MODEL_ROLES.agent.model,\n        preferredProvider: MODEL_ROLES.agent.provider,\n        reason: \"symposium:crystallize\",\n        maxTokens: 800,\n        meta: { modelRole: \"agent\" },\n      });\n\n      let brief: { projectName: string; summary: string; taskList: string[]; source: string };\n      try {\n        brief = JSON.parse(result.text) as typeof brief;\n      } catch {\n        return reply.status(422).send({ ok: false, error: \"Model did not return valid JSON\", raw: result.text });\n      }\n\n      req.log.info({ event: \"symposium:crystallize\", sessionId, projectName: brief.projectName, durationMs: Date.now() - t0 });\n      return reply.send({ ok: true, brief, meta: { tokensIn: result.tokensIn, tokensOut: result.tokensOut, durationMs: result.durationMs, costUsd: result.estimatedCostUsd } });\n    } catch (err) {\n      req.log.error({ event: \"symposium:crystallize-failed\", error: String(err) });\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Fabrica — receive handoff from Symposium ──────────────────────────────\n\n  app.post<{\n    Body: {\n      brief: { projectName: string; summary: string; taskList: string[]; source: string };\n      sessionId?: string;\n    }\n  }>(\"/fabrica/receive-handoff\", async (req, reply) => {\n    const { writeFile, mkdir, readFile } = await import(\"node:fs/promises\");\n    const { join, resolve }              = await import(\"node:path\");\n    try {\n      const { brief, sessionId } = req.body;\n      if (!brief?.projectName) return reply.status(400).send({ ok: false, error: \"brief required\" });\n\n      const fabricaDir = resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"fabrica\");\n      await mkdir(fabricaDir, { recursive: true });\n\n      const id        = `fab-${Date.now().toString(36)}`;\n      const timestamp = new Date().toISOString();\n      const entry     = { id, timestamp, status: \"pending-approval\", sessionId, brief };\n\n      // Append to daily JSONL\n      const today = timestamp.slice(0, 10);\n      await writeFile(join(fabricaDir, `briefs-${today}.jsonl`), JSON.stringify(entry) + \"\\n\", { flag: \"a\" });\n\n      req.log.info({ event: \"fabrica:receive-handoff\", id, projectName: brief.projectName });\n      return reply.send({ ok: true, id, timestamp });\n    } catch (err) {\n      req.log.error({ event: \"fabrica:receive-handoff-failed\", error: String(err) });\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  app.get<{ Querystring: { date?: string; status?: string } }>(\"/fabrica/briefs\", async (req, reply) => {\n    const { readdir, readFile } = await import(\"node:fs/promises\");\n    const { join, resolve }     = await import(\"node:path\");\n    try {\n      const fabricaDir = resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"fabrica\");\n      const { date, status } = req.query;\n      const files = await readdir(fabricaDir).catch(() => [] as string[]);\n      const targetFile = date\n        ? `briefs-${date}.jsonl`\n        : files.filter(f => f.startsWith(\"briefs-\") && f.endsWith(\".jsonl\")).sort().reverse()[0];\n      if (!targetFile) return reply.send({ ok: true, briefs: [], dates: [] });\n      const raw = await readFile(join(fabricaDir, targetFile), \"utf-8\").catch(() => \"\");\n      let briefs = raw.split(\"\\n\").filter(Boolean).map(l => { try { return JSON.parse(l); } catch { return null; } }).filter(Boolean);\n      if (status) briefs = briefs.filter((b: { status: string }) => b.status === status);\n      const dates = files.filter(f => f.startsWith(\"briefs-\") && f.endsWith(\".jsonl\")).map(f => f.replace(\"briefs-\", \"\").replace(\".jsonl\", \"\")).sort().reverse();\n      return reply.send({ ok: true, briefs: briefs.reverse(), dates });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  app.patch<{ Params: { id: string }; Body: { status: string; lastTaskIndex?: number } }>(\"/fabrica/briefs/:id\", async (req, reply) => {\n    const { readdir, readFile, writeFile, mkdir: mkd } = await import(\"node:fs/promises\");\n    const { join, resolve }               = await import(\"node:path\");\n    try {\n      const fabricaDir = resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"fabrica\");\n      const { id } = req.params;\n      const { status, lastTaskIndex } = req.body;\n      if (!status) return reply.status(400).send({ ok: false, error: \"status required\" });\n      const files = await readdir(fabricaDir).catch(() => [] as string[]);\n      for (const file of files.filter(f => f.startsWith(\"briefs-\") && f.endsWith(\".jsonl\"))) {\n        const path = join(fabricaDir, file);\n        const raw  = await readFile(path, \"utf-8\").catch(() => \"\");\n        const lines = raw.split(\"\\n\").filter(Boolean);\n        const idx = lines.findIndex(l => { try { return JSON.parse(l).id === id; } catch { return false; } });\n        if (idx === -1) continue;\n        const entry = JSON.parse(lines[idx]!);\n        const prevStatus = entry.status;\n        entry.status = status;\n        if (lastTaskIndex !== undefined) entry.lastTaskIndex = lastTaskIndex;\n        if (status === \"approved\" && prevStatus === \"pending-approval\") {\n          entry.approvedAt = new Date().toISOString();\n        }\n        if (status === \"failed\") {\n          entry.failedAt = new Date().toISOString();\n        }\n        lines[idx] = JSON.stringify(entry);\n        await writeFile(path, lines.join(\"\\n\") + \"\\n\", \"utf-8\");\n\n        // Persist approved brief as recoverable project save point\n        if (status === \"approved\" || status === \"in-progress\" || status === \"failed\" || status === \"done\") {\n          const projectDir = join(resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\"), \"projects\", id);\n          await mkd(projectDir, { recursive: true });\n          await writeFile(join(projectDir, \"brief.json\"), JSON.stringify({\n            ...entry,\n            savedAt: new Date().toISOString(),\n          }, null, 2), \"utf-8\");\n        }\n\n        return reply.send({ ok: true });\n      }\n      return reply.status(404).send({ ok: false, error: \"brief not found\" });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Fabrica — delete single brief ────────────────────────────────────────\n\n  app.delete<{ Params: { id: string } }>(\"/fabrica/briefs/:id\", async (req, reply) => {\n    const { readdir, readFile, writeFile, rm } = await import(\"node:fs/promises\");\n    const { join, resolve } = await import(\"node:path\");\n    try {\n      const fabricaDir = resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"fabrica\");\n      const { id } = req.params;\n      let found = false;\n      const files = await readdir(fabricaDir).catch(() => [] as string[]);\n      for (const file of files.filter(f => f.startsWith(\"briefs-\") && f.endsWith(\".jsonl\"))) {\n        const path = join(fabricaDir, file);\n        const raw = await readFile(path, \"utf-8\").catch(() => \"\");\n        const lines = raw.split(\"\\n\").filter(Boolean);\n        const filtered = lines.filter(l => { try { return JSON.parse(l).id !== id; } catch { return true; } });\n        if (filtered.length < lines.length) {\n          found = true;\n          if (filtered.length === 0) {\n            const { unlink } = await import(\"node:fs/promises\");\n            await unlink(path).catch(() => {});\n          } else {\n            await writeFile(path, filtered.join(\"\\n\") + \"\\n\", \"utf-8\");\n          }\n        }\n      }\n      // Also delete the project folder if it exists\n      const projectDir = join(resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\"), \"projects\", id);\n      await rm(projectDir, { recursive: true, force: true }).catch(() => {});\n      return found ? reply.send({ ok: true }) : reply.status(404).send({ ok: false, error: \"brief not found\" });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Fabrica — delete all briefs ────────────────────────────────────────────\n\n  app.delete(\"/fabrica/briefs\", async (_req, reply) => {\n    const { readdir, unlink, rm } = await import(\"node:fs/promises\");\n    const { join, resolve } = await import(\"node:path\");\n    try {\n      const fabricaDir = resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"fabrica\");\n      const files = await readdir(fabricaDir).catch(() => [] as string[]);\n      let deleted = 0;\n      for (const file of files.filter(f => f.startsWith(\"briefs-\") && f.endsWith(\".jsonl\"))) {\n        await unlink(join(fabricaDir, file)).catch(() => {});\n        deleted++;\n      }\n      // Also delete all project folders (fab-*)\n      const projectsDir = resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"projects\");\n      const dirs = await readdir(projectsDir, { withFileTypes: true }).catch(() => []);\n      for (const d of dirs) {\n        if (d.isDirectory() && d.name.startsWith(\"fab-\")) {\n          await rm(join(projectsDir, d.name), { recursive: true, force: true }).catch(() => {});\n        }\n      }\n      return reply.send({ ok: true, deleted });\n    } catch (err) {\n      return reply.status(500).send({ ok: false, error: String(err) });\n    }\n  });\n\n  // ── Fabrica — list saved projects with briefs ────────────────────────────\n\n  app.get(\"/fabrica/projects\", async (_req, reply) => {\n    const { readdir, readFile } = await import(\"node:fs/promises\");\n    const { join, resolve }     = await import(\"node:path\");\n    try {\n      const projectsDir = resolve(process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"./state\", \"projects\");\n      const dirs = await readdir(projectsDir, { withFileTypes: true }).catch(() => []);\n      const projects: Array<Record<string, unknown>> = [];\n      for (const d of dirs) {\n        if (!d.isDirectory()) continue;\n        try {\n          const raw = await readFile(join(projectsDir, d.name, \"brief.json\"), \"utf-8\");\n          projects.push(JSON.parse(raw));\n        } catch { /* skip malformed */ }\n      }\n      projects.sort((a, b) => String(b.savedAt ?? \"\").localeCompare(String(a.savedAt ?? \"\")));\n      return reply.send({ ok: true, projects });\n    } catch (err) {\n      return reply.send({ ok: true, projects: [], error: String(err) });\n    }\n  });\n\n  // ── Colloquium health + contract ────────────────────────────────────────────\n\n  app.get(\"/colloquium/health\", async (_req, reply) => {\n    const pm = getService<{ getRegisteredProviders: () => string[] }>(\"provider-manager\");\n    const providers = pm?.getRegisteredProviders() ?? [];\n    const hasModels = providers.length > 0;\n    const memory = getService<{ getWorkingMemory: () => unknown[] }>(\"memory\");\n    const memoryOk = !!memory;\n\n    let trust: \"trusted\" | \"verified\" | \"degraded\";\n    let message: string;\n\n    if (hasModels && memoryOk) {\n      trust = \"trusted\";\n      message = `${providers.length} provider(s) available, memory active`;\n    } else if (hasModels) {\n      trust = \"verified\";\n      message = `${providers.length} provider(s) available, memory offline`;\n    } else {\n      trust = \"degraded\";\n      message = \"No models available. Run: ollama pull qwen3.5:4b\";\n    }\n\n    return reply.send({\n      ok: true,\n      trust,\n      message,\n      contract: {\n        promise: \"Primary conversational interface — always available if at least one model exists\",\n        proofPath: \"receipts — every conversation logged with model, tokens, cost\",\n        degradedBehavior: \"Shows clear error if no models available with setup instructions\",\n        failureOwner: \"colloquium\",\n      },\n      providers: providers.length,\n      memoryAvailable: memoryOk,\n    });\n  });\n\n}\n",
